_active_diag_session_id: str | None = None


# ─── PHASE E: CODEBASE INDEX FOUNDATION ─────────────────────────────────────

_CODE_INDEX_ALLOWED_SUFFIXES = {
    ".py", ".json", ".md", ".txt", ".toml", ".yaml", ".yml", ".ini", ".cfg", ".sh",
    ".js", ".jsx", ".ts", ".tsx", ".css", ".html",
}

_CODE_INDEX_IGNORE_DIRS = {
    ".git", ".hg", ".svn", ".venv", "venv", "env", "node_modules", "__pycache__",
    ".pytest_cache", ".mypy_cache", ".ruff_cache", ".cache", "dist", "build", "target",
    "logs", "log", "chroma_db", "context_library_v1", "code_library_v1",
}

_CODE_INDEX_SENSITIVE_FILE_NAMES = {
    ".env", ".env.local", ".env.production", ".npmrc", ".pypirc", ".netrc",
    "id_rsa", "id_dsa", "id_ecdsa", "id_ed25519", "known_hosts",
}

_CODE_INDEX_SENSITIVE_SUBSTRINGS = (
    "secret", "secrets", "credential", "credentials", "private_key", "private-key",
    "access_token", "refresh_token", "auth_token", "api_token", "api-key", "apikey",
)

_CODE_INDEX_MAX_FILE_BYTES = 512 * 1024
_CODE_INDEX_CHUNK_CHAR_TARGET = 4200
_CODE_INDEX_CHUNK_LINE_TARGET = 140


def _code_library_ensure_dirs() -> None:
    for d in (CODE_LIBRARY_DIR, CODE_INDEXES_DIR, CODE_MANIFESTS_DIR, CODE_PLANS_DIR,
              CODE_RECEIPTS_DIR, CODE_SYMBOLIC_MAPS_DIR, CODE_CHROMA_DIR):
        d.mkdir(parents=True, exist_ok=True)


def _code_now_id() -> str:
    return datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")


def _code_sha256_16_bytes(raw: bytes) -> str:
    import hashlib
    return hashlib.sha256(raw).hexdigest()[:16]


def _code_sha256_16_text(text: str) -> str:
    import hashlib
    return hashlib.sha256(text.encode("utf-8", errors="replace")).hexdigest()[:16]


def _code_is_sensitive_path(path: Path) -> tuple[bool, str]:
    parts = [p.lower() for p in path.parts]
    name = path.name.lower()
    if name in _CODE_INDEX_SENSITIVE_FILE_NAMES:
        return True, f"sensitive filename: {path.name}"
    if name.endswith((".pem", ".key", ".crt", ".p12", ".pfx", ".kdbx")):
        return True, f"sensitive extension: {path.name}"
    joined = "/".join(parts)
    for token in _CODE_INDEX_SENSITIVE_SUBSTRINGS:
        if token in joined:
            return True, f"sensitive token in path: {token}"
    return False, ""


def _code_should_skip_dir(dirname: str) -> bool:
    return dirname.lower() in _CODE_INDEX_IGNORE_DIRS


def _code_is_readme_or_manifest(path: Path) -> bool:
    lower = path.name.lower()
    if lower.startswith("readme"):
        return True
    if "manifest" in lower:
        return True
    if lower in ("pyproject.toml", "package.json", "requirements.txt", "setup.py", "setup.cfg"):
        return True
    return False


def _code_file_role(path: Path, rel: str) -> str:
    lower = (rel + "/" + path.name).lower()
    name = path.name.lower()
    if name.startswith("test_") or "/tests/" in lower or "/test/" in lower or name.endswith("_test.py"):
        return "test_file"
    if "engine" in lower:
        return "engine_definition"
    if "wrapper" in lower or "runtime" in lower or name in ("main.py", "cli.py", "run.py"):
        return "runtime_wrapper"
    if _code_is_readme_or_manifest(path):
        return "readme_or_manifest"
    if path.suffix.lower() == ".json" or "config" in lower:
        return "config_or_manifest"
    if path.suffix.lower() == ".py":
        return "python_module"
    return "text_code_file"


def _code_read_session_scope_roots() -> list[Path]:
    roots = []
    try:
        data = _load_json(SESSION_SCOPE_FILE)
        for raw in data.get("paths", []) or []:
            p = Path(os.path.realpath(os.path.abspath(os.path.expanduser(str(raw)))))
            if p.exists() and p.is_dir():
                roots.append(p)
    except Exception:
        pass
    return roots


def _code_resolve_scan_roots(target: str = "") -> tuple[list[Path], list[str]]:
    """Return scope-safe scan roots and warnings. Default is active session scope."""
    from agents.forge.permissions import is_path_allowed, is_path_blocked
    warnings = []
    target = (target or "").strip()
    if not target or target.lower() in ("scope", "session", "current"):
        roots = _code_read_session_scope_roots()
        if not roots:
            warnings.append("No active session scope found; run inside Forge after choosing /home/nic/aiweb.")
        return roots, warnings
    p = Path(os.path.realpath(os.path.abspath(os.path.expanduser(target))))
    blocked, reason = is_path_blocked(str(p))
    if blocked:
        return [], [f"blocked path: {reason}"]
    allowed, reason = is_path_allowed(str(p))
    if not allowed:
        return [], [f"out of scope: {reason}"]
    if not p.exists():
        return [], [f"path does not exist: {p}"]
    if p.is_file():
        return [p], warnings
    if p.is_dir():
        return [p], warnings
    return [], [f"path is neither regular file nor directory: {p}"]


def _code_iter_candidate_files(root: Path):
    if root.is_file():
        yield root
        return
    for dirpath, dirnames, filenames in os.walk(root):
        # mutate in-place so os.walk will not descend into ignored directories
        dirnames[:] = [d for d in dirnames if not _code_should_skip_dir(d)]
        for filename in filenames:
            yield Path(dirpath) / filename


def _code_read_text_file(path: Path) -> tuple[bool, str, bytes | None, str | None]:
    try:
        raw = path.read_bytes()
    except Exception as e:
        return False, f"read failed: {e}", None, None
    if len(raw) > _CODE_INDEX_MAX_FILE_BYTES:
        return False, f"large file skipped: {len(raw)} bytes > {_CODE_INDEX_MAX_FILE_BYTES}", raw, None
    if b"\x00" in raw[:4096]:
        return False, "binary/null-byte file skipped", raw, None
    try:
        text = raw.decode("utf-8")
    except UnicodeDecodeError:
        try:
            text = raw.decode("utf-8", errors="replace")
        except Exception as e:
            return False, f"decode failed: {e}", raw, None
    return True, "ok", raw, text


def _code_extract_python_symbols(text: str, rel: str) -> list[dict]:
    import ast
    symbols = []
    try:
        tree = ast.parse(text)
    except Exception:
        return symbols
    for node in ast.walk(tree):
        kind = None
        if isinstance(node, ast.ClassDef):
            kind = "class"
        elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            kind = "function"
        if kind:
            symbols.append({
                "symbol": node.name,
                "kind": kind,
                "relative_path": rel,
                "line": int(getattr(node, "lineno", 0) or 0),
                "end_line": int(getattr(node, "end_lineno", 0) or 0),
            })
    return symbols


def _code_extract_text_symbols(text: str, rel: str) -> list[dict]:
    symbols = []
    # Conservative non-Python extraction: JSON/TOML/YAML-ish top-level keys and markdown headings.
    for i, line in enumerate(text.splitlines(), 1):
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.startswith("#"):
            heading = stripped.lstrip("#").strip()
            if heading:
                symbols.append({"symbol": heading[:120], "kind": "heading", "relative_path": rel, "line": i, "end_line": i})
        elif re.match(r'^[A-Za-z0-9_\-\.]+\s*[:=]', stripped):
            key = re.split(r'[:=]', stripped, 1)[0].strip()
            if key and len(key) <= 80:
                symbols.append({"symbol": key, "kind": "key", "relative_path": rel, "line": i, "end_line": i})
        if len(symbols) >= 80:
            break
    return symbols


def _code_chunk_text(text: str, rel: str, sha16: str) -> list[dict]:
    chunks = []
    lines = text.splitlines()
    if not lines:
        lines = [""]
    start_idx = 0
    chunk_index = 0
    while start_idx < len(lines):
        char_count = 0
        end_idx = start_idx
        while end_idx < len(lines) and (end_idx - start_idx) < _CODE_INDEX_CHUNK_LINE_TARGET:
            char_count += len(lines[end_idx]) + 1
            end_idx += 1
            if char_count >= _CODE_INDEX_CHUNK_CHAR_TARGET:
                break
        chunk_lines = lines[start_idx:end_idx]
        chunk_text = "\n".join(chunk_lines).strip("\n")
        chunk_sha = _code_sha256_16_text(chunk_text)
        chunks.append({
            "chunk_id": f"code_{sha16}_{chunk_index:04d}",
            "relative_path": rel,
            "chunk_index": chunk_index,
            "line_start": start_idx + 1,
            "line_end": max(start_idx + 1, end_idx),
            "char_count": len(chunk_text),
            "chunk_sha256_16": chunk_sha,
            "text": chunk_text,
        })
        chunk_index += 1
        start_idx = max(end_idx, start_idx + 1)
    return chunks


def _code_scan_roots(roots: list[Path]) -> dict:
    from agents.forge.permissions import is_path_allowed, is_path_blocked
    files = []
    chunks = []
    symbols = []
    skipped = []
    seen = set()
    for root in roots:
        root = Path(os.path.realpath(str(root)))
        root_base = root if root.is_dir() else root.parent
        for path in _code_iter_candidate_files(root):
            try:
                path = Path(os.path.realpath(str(path)))
            except Exception:
                continue
            if str(path) in seen:
                continue
            seen.add(str(path))
            blocked, reason = is_path_blocked(str(path))
            if blocked:
                skipped.append({"path": str(path), "reason": f"blocked: {reason}"})
                continue
            allowed, reason = is_path_allowed(str(path))
            if not allowed:
                skipped.append({"path": str(path), "reason": f"out of scope: {reason}"})
                continue
            sensitive, reason = _code_is_sensitive_path(path)
            if sensitive:
                skipped.append({"path": str(path), "reason": reason})
                continue
            suffix = path.suffix.lower()
            if suffix not in _CODE_INDEX_ALLOWED_SUFFIXES and not _code_is_readme_or_manifest(path):
                skipped.append({"path": str(path), "reason": f"unsupported suffix: {suffix or '(none)'}"})
                continue
            ok, msg, raw, text = _code_read_text_file(path)
            if not ok:
                skipped.append({"path": str(path), "reason": msg})
                continue
            try:
                rel = str(path.relative_to(root_base))
            except Exception:
                rel = path.name
            sha16 = _code_sha256_16_bytes(raw or b"")
            role = _code_file_role(path, rel)
            line_count = len((text or "").splitlines())
            file_chunks = _code_chunk_text(text or "", rel, sha16)
            for c in file_chunks:
                c.update({
                    "absolute_path": str(path),
                    "file_sha256_16": sha16,
                    "file_role": role,
                    "collection_namespace": AIWEB_CODE_CHUNKS_COLLECTION,
                })
            file_symbols = _code_extract_python_symbols(text or "", rel) if suffix == ".py" else _code_extract_text_symbols(text or "", rel)
            for sym in file_symbols:
                sym.update({
                    "absolute_path": str(path),
                    "file_sha256_16": sha16,
                    "file_role": role,
                    "collection_namespace": AIWEB_CODE_SYMBOLS_COLLECTION,
                })
            files.append({
                "absolute_path": str(path),
                "relative_path": rel,
                "filename": path.name,
                "suffix": suffix,
                "size_bytes": len(raw or b""),
                "sha256_16": sha16,
                "line_count": line_count,
                "file_role": role,
                "chunk_count": len(file_chunks),
                "symbol_count": len(file_symbols),
                "mtime": datetime.datetime.fromtimestamp(path.stat().st_mtime).isoformat(timespec="seconds"),
            })
            chunks.extend(file_chunks)
            symbols.extend(file_symbols)
    roles = {}
    for f in files:
        roles[f["file_role"]] = roles.get(f["file_role"], 0) + 1
    return {
        "generated_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "library_path": str(CODE_LIBRARY_DIR),
        "collections": {
            "chunks": AIWEB_CODE_CHUNKS_COLLECTION,
            "symbols": AIWEB_CODE_SYMBOLS_COLLECTION,
            "patch_history": AIWEB_PATCH_HISTORY_COLLECTION,
        },
        "roots": [str(r) for r in roots],
        "files": files,
        "chunks": chunks,
        "symbols": symbols,
        "skipped": skipped,
        "stats": {
            "files": len(files),
            "chunks": len(chunks),
            "symbols": len(symbols),
            "skipped": len(skipped),
            "roles": roles,
        },
        "guardrails": {
            "ignored_dirs": sorted(_CODE_INDEX_IGNORE_DIRS),
            "sensitive_file_names": sorted(_CODE_INDEX_SENSITIVE_FILE_NAMES),
            "sensitive_substrings": list(_CODE_INDEX_SENSITIVE_SUBSTRINGS),
            "max_file_bytes": _CODE_INDEX_MAX_FILE_BYTES,
            "old_chroma_db_untouched": str(MEMORY_DIR / "chroma_db"),
            "code_chroma_reserved_no_vector_write_patch57": str(CODE_CHROMA_DIR),
        },
    }


def _code_latest_file(directory: Path, pattern: str) -> Path | None:
    try:
        hits = sorted(directory.glob(pattern), key=lambda p: p.stat().st_mtime)
    except Exception:
        return None
    return hits[-1] if hits else None


def _code_write_json(path: Path, data) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2, ensure_ascii=False), encoding="utf-8")


def _code_write_jsonl(path: Path, rows: list[dict]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", encoding="utf-8") as f:
        for row in rows:
            f.write(json.dumps(row, ensure_ascii=False) + "\n")


def _code_load_plan(ref: str = "latest") -> tuple[dict | None, Path | None, str | None]:
    _code_library_ensure_dirs()
    ref = (ref or "latest").strip()
    if not ref or ref.lower() == "latest":
        p = _code_latest_file(CODE_PLANS_DIR, "*_code_index_plan.json")
    else:
        candidate = Path(os.path.expanduser(ref))
        if not candidate.is_absolute():
            candidate = CODE_PLANS_DIR / ref
        p = candidate
    if not p or not p.exists():
        return None, p, "plan not found"
    try:
        return json.loads(p.read_text(encoding="utf-8")), p, None
    except Exception as e:
        return None, p, f"plan read failed: {e}"


def _code_index_current_manifest() -> dict | None:
    p = CODE_MANIFESTS_DIR / "_code_index_current.json"
    if not p.exists():
        return None
    try:
        return json.loads(p.read_text(encoding="utf-8"))
    except Exception:
        return None


def _code_patch_history_rows() -> list[dict]:
    rows = []
    artifact_dirs = [FORGE_ROOT / "proposed_patches", FORGE_ROOT / "apply_plans", FORGE_ROOT / "rollback_registry"]
    for d in artifact_dirs:
        if not d.exists():
            continue
        for p in sorted(d.rglob("*")):
            if not p.is_file():
                continue
            sensitive, reason = _code_is_sensitive_path(p)
            if sensitive:
                continue
            if p.suffix.lower() not in {".txt", ".json", ".md", ".diff", ".patch"}:
                continue
            try:
                raw = p.read_bytes()
            except Exception:
                continue
            if len(raw) > _CODE_INDEX_MAX_FILE_BYTES or b"\x00" in raw[:4096]:
                continue
            rows.append({
                "absolute_path": str(p),
                "relative_path": str(p.relative_to(FORGE_ROOT)),
                "artifact_area": d.name,
                "filename": p.name,
                "size_bytes": len(raw),
                "sha256_16": _code_sha256_16_bytes(raw),
                "collection_namespace": AIWEB_PATCH_HISTORY_COLLECTION,
                "mtime": datetime.datetime.fromtimestamp(p.stat().st_mtime).isoformat(timespec="seconds"),
            })
    return rows


