def _code_search_score(text: str, query_terms: list[str]) -> tuple[float, list[str]]:
    lower = text.lower()
    hits = []
    for t in query_terms:
        if t and t in lower:
            hits.append(t)
    if not query_terms:
        return 0.0, []
    return len(set(hits)) / max(1, len(set(query_terms))), sorted(set(hits))


def _code_search_load_chunks() -> list[dict]:
    p = CODE_INDEXES_DIR / "code_chunks.jsonl"
    if not p.exists():
        return []
    rows = []
    try:
        for line in p.read_text(encoding="utf-8").splitlines():
            if line.strip():
                rows.append(json.loads(line))
    except Exception:
        return []
    return rows


def cmd_code_index_search(query: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    query = (query or "").strip()
    if not query:
        print()
        print("  Usage: code-index-search <query>")
        print("  Example: code-index-search collapse handler")
        print()
        return
    rows = _code_search_load_chunks()
    if not rows:
        print()
        print("[forge] No code index found yet. Run code-index-plan, code-index-dry-run, code-index-apply first.")
        print()
        write_audit_entry(session_id, "CODE_INDEX_SEARCH_EMPTY", str(CODE_LIBRARY_DIR), "0 results", "index missing")
        return
    terms = [t.lower() for t in re.findall(r"[A-Za-z0-9_]+", query) if len(t) > 1]
    ranked = []
    for r in rows:
        blob = " ".join([str(r.get("relative_path", "")), str(r.get("file_role", "")), str(r.get("text", ""))])
        score, hits = _code_search_score(blob, terms)
        if score > 0:
            ranked.append((score, len(hits), r, hits))
    ranked.sort(key=lambda x: (-x[0], -x[1], str(x[2].get("relative_path", "")), int(x[2].get("chunk_index", 0))))
    shown = ranked[:5]
    print()
    print("── Code Index Search ────────────────────────────────")
    print(f"  Query     : {query}")
    print(f"  Results   : {len(shown)}/{len(ranked)} shown")
    print(f"  Read-only : YES")
    print()
    for i, (score, _hit_count, r, hits) in enumerate(shown, 1):
        snippet = " ".join((r.get("text", "") or "").split())[:260]
        print(f"  [{i}] score={score:.3f} hits={', '.join(hits[:8])}")
        print(f"      file : {r.get('relative_path')}")
        print(f"      role : {r.get('file_role')}  lines={r.get('line_start')}-{r.get('line_end')}")
        print(f"      chunk: {r.get('chunk_id')}")
        print(f"      text : {snippet}")
        print()
    if not shown:
        print("  No matching indexed code chunks found.")
        print()
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "CODE_INDEX_SEARCH_SHOWN", query, f"{len(shown)} results", f"matches={len(ranked)}")


