# ─── PATCH 58: CODE INDEX INTEGRITY + ENGINE INVENTORY ───────────────────────

def _code_index_read_json_file(path: Path, fallback):
    """Read a Forge-owned code index JSON file. Read-only helper for Patch 58."""
    try:
        if not path.exists():
            return fallback, f"missing: {path}"
        return json.loads(path.read_text(encoding="utf-8")), None
    except Exception as e:
        return fallback, f"read failed: {path}: {e}"


def _code_index_read_jsonl_file(path: Path, max_rows: int | None = None) -> tuple[list[dict], str | None]:
    """Read a Forge-owned code index JSONL file. Read-only helper for Patch 58."""
    rows: list[dict] = []
    try:
        if not path.exists():
            return rows, f"missing: {path}"
        with path.open("r", encoding="utf-8", errors="replace") as f:
            for i, line in enumerate(f, 1):
                if max_rows is not None and len(rows) >= max_rows:
                    break
                line = line.strip()
                if not line:
                    continue
                try:
                    rows.append(json.loads(line))
                except Exception as e:
                    return rows, f"jsonl parse failed at line {i}: {e}"
        return rows, None
    except Exception as e:
        return rows, f"read failed: {path}: {e}"


def _code_index_paths() -> dict[str, Path]:
    return {
        "manifest": CODE_MANIFESTS_DIR / "_code_index_current.json",
        "files": CODE_INDEXES_DIR / "code_files.json",
        "chunks": CODE_INDEXES_DIR / "code_chunks.jsonl",
        "symbols": CODE_INDEXES_DIR / "code_symbols.json",
        "patch_history": CODE_INDEXES_DIR / "patch_history.json",
    }


def _code_load_current_indexes(load_chunks: bool = False) -> tuple[dict, list[str]]:
    """Load current Forge-owned code index artifacts. Does not touch Chroma."""
    paths = _code_index_paths()
    errors: list[str] = []
    manifest, err = _code_index_read_json_file(paths["manifest"], {})
    if err: errors.append(err)
    files, err = _code_index_read_json_file(paths["files"], [])
    if err: errors.append(err)
    symbols, err = _code_index_read_json_file(paths["symbols"], [])
    if err: errors.append(err)
    patch_history, err = _code_index_read_json_file(paths["patch_history"], [])
    if err: errors.append(err)
    chunks: list[dict] = []
    chunk_error = None
    if load_chunks:
        chunks, chunk_error = _code_index_read_jsonl_file(paths["chunks"])
    else:
        if not paths["chunks"].exists():
            chunk_error = f"missing: {paths['chunks']}"
        else:
            try:
                with paths["chunks"].open("r", encoding="utf-8", errors="replace") as f:
                    chunk_count = sum(1 for line in f if line.strip())
                chunks = [{"_count_only": chunk_count}]
            except Exception as e:
                chunk_error = f"chunk count failed: {e}"
    if chunk_error: errors.append(chunk_error)
    return {
        "manifest": manifest if isinstance(manifest, dict) else {},
        "files": files if isinstance(files, list) else [],
        "chunks": chunks,
        "symbols": symbols if isinstance(symbols, list) else [],
        "patch_history": patch_history if isinstance(patch_history, list) else [],
        "paths": paths,
        "chunks_loaded_full": load_chunks,
    }, errors


def _code_engine_base_name(engine_name: str) -> str:
    """Normalize frozen/versioned engine names into a comparison key."""
    name = (engine_name or "").strip().replace("-", "_").lower()
    name = re.sub(r"_frozen_v[0-9][a-z0-9_\.\-]*$", "", name)
    name = re.sub(r"_frozen$", "", name)
    name = re.sub(r"_v[0-9]+(?:[\._\-][0-9a-z]+)*$", "", name)
    name = re.sub(r"_(copy|backup|bak|old|archive)$", "", name)
    name = re.sub(r"__+", "_", name).strip("_")
    return name or "unknown"


def _code_engine_root_from_relative_path(rel: str) -> tuple[str | None, str | None, str | None]:
    """Return (engine_name, engine_root, engine_family) for an indexed path."""
    parts = [x for x in str(rel or "").split("/") if x]
    if not parts:
        return None, None, None
    for marker in ("engines", "runtime_wrappers", "agents", "symbolic_layers"):
        if marker in parts:
            idx = parts.index(marker)
            if idx + 1 < len(parts):
                name = parts[idx + 1]
                # A direct file under engines/ is not an engine root.
                # Engine roots must be directories or named manifest-like roots.
                if idx + 2 >= len(parts) and Path(name).suffix:
                    return None, None, None
                root = "/".join(parts[:idx + 2])
                return name, root, marker
    return None, None, None


def _code_engine_status_tags(engine_name: str, root: str, rows: list[dict]) -> list[str]:
    blob = " ".join([engine_name or "", root or ""] + [str(r.get("relative_path", "")) for r in rows[:8]]).lower()
    tags = []
    if "frozen" in blob:
        tags.append("frozen")
    if any(x in blob for x in ["backup", "bak", "archive", "old", "copy"]):
        tags.append("backup_or_archive")
    if all(str(r.get("file_role")) == "test_file" for r in rows):
        tags.append("test_only")
    if any("site-packages" in str(r.get("relative_path", "")) for r in rows):
        tags.append("external_dependency")
    if not tags:
        tags.append("active_or_unfrozen")
    return tags


def _code_engine_canonical_score(engine: dict) -> int:
    """Higher score means better canonical candidate. Conservative, explainable heuristic."""
    score = 0
    root = str(engine.get("root", "")).lower()
    name = str(engine.get("engine_name", "")).lower()
    tags = set(engine.get("status_tags", []))
    if root.startswith("aiweb/engines/"):
        score += 50
    if root.startswith("engines/"):
        score += 45
    if "/engines/" in root:
        score += 35
    if "active_or_unfrozen" in tags:
        score += 25
    if "frozen" in tags:
        score += 10
    if "backup_or_archive" in tags:
        score -= 25
    if "test_only" in tags:
        score -= 20
    if "external_dependency" in tags:
        score -= 100
    score += min(20, int(engine.get("file_count", 0)))
    score += min(10, int(engine.get("symbol_count", 0)) // 5)
    if "frozen" not in name:
        score += 5
    return score


def _code_engine_inventory_rows() -> tuple[list[dict], list[str]]:
    """Build a read-only inventory from code_files.json."""
    data, errors = _code_load_current_indexes(load_chunks=False)
    files = data.get("files", [])
    grouped: dict[str, dict] = {}
    for f in files:
        name, root, family = _code_engine_root_from_relative_path(str(f.get("relative_path", "")))
        if not name or not root:
            continue
        rec = grouped.setdefault(root, {
            "engine_name": name,
            "engine_base": _code_engine_base_name(name),
            "root": root,
            "family": family,
            "file_count": 0,
            "chunk_count": 0,
            "symbol_count": 0,
            "roles": {},
            "suffixes": {},
            "files": [],
            "absolute_roots": set(),
        })
        rec["file_count"] += 1
        rec["chunk_count"] += int(f.get("chunk_count", 0) or 0)
        rec["symbol_count"] += int(f.get("symbol_count", 0) or 0)
        role = str(f.get("file_role", "unknown"))
        rec["roles"][role] = rec["roles"].get(role, 0) + 1
        suffix = str(f.get("suffix", "")) or "(none)"
        rec["suffixes"][suffix] = rec["suffixes"].get(suffix, 0) + 1
        rec["files"].append(f)
        abs_path = str(f.get("absolute_path", ""))
        if abs_path and root in abs_path:
            rec["absolute_roots"].add(abs_path.split(root, 1)[0] + root)
    rows = []
    for rec in grouped.values():
        rec["status_tags"] = _code_engine_status_tags(rec["engine_name"], rec["root"], rec["files"])
        rec["canonical_score"] = _code_engine_canonical_score(rec)
        rec["absolute_roots"] = sorted(rec["absolute_roots"])
        # Keep memory bounded for display commands.
        rec["sample_files"] = [r.get("relative_path") for r in rec["files"][:8]]
        rec.pop("files", None)
        rows.append(rec)
    rows.sort(key=lambda r: (r.get("engine_base", ""), -int(r.get("canonical_score", 0)), r.get("root", "")))
    return rows, errors


def _code_engine_duplicate_groups(rows: list[dict]) -> list[dict]:
    groups: dict[str, list[dict]] = {}
    for r in rows:
        groups.setdefault(str(r.get("engine_base", "unknown")), []).append(r)
    out = []
    for base, items in groups.items():
        if len(items) < 2:
            continue
        ranked = sorted(items, key=lambda r: (-int(r.get("canonical_score", 0)), r.get("root", "")))
        out.append({"engine_base": base, "canonical_candidate": ranked[0], "variants": ranked})
    out.sort(key=lambda g: (-len(g["variants"]), g["engine_base"]))
    return out


def _code_engine_write_report(name: str, payload: dict) -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    p = CODE_MANIFESTS_DIR / f"{ts}_{name}.json"
    p.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return p


def cmd_code_index_integrity(session_id: str) -> None:
    """Read-only integrity check for Patch 57 code index artifacts."""
    from agents.forge.memory import write_audit_entry
    data, errors = _code_load_current_indexes(load_chunks=True)
    manifest = data["manifest"]
    stats = manifest.get("stats", {}) if isinstance(manifest, dict) else {}
    files = data["files"]
    chunks = data["chunks"]
    symbols = data["symbols"]
    patch_history = data["patch_history"]
    file_paths = {str(f.get("relative_path", "")) for f in files}
    file_sha = {str(f.get("sha256_16", "")) for f in files}
    chunk_bad_refs = [c for c in chunks if c.get("relative_path") not in file_paths or c.get("file_sha256_16") not in file_sha]
    symbol_bad_refs = [s for s in symbols if s.get("relative_path") not in file_paths or s.get("file_sha256_16") not in file_sha]
    duplicate_file_hashes = {}
    seen_hash_paths: dict[str, list[str]] = {}
    for f in files:
        seen_hash_paths.setdefault(str(f.get("sha256_16", "")), []).append(str(f.get("relative_path", "")))
    for h, paths in seen_hash_paths.items():
        if h and len(paths) > 1:
            duplicate_file_hashes[h] = paths[:10]
    actual = {
        "files": len(files),
        "chunks": len(chunks),
        "symbols": len(symbols),
        "patch_history": len(patch_history),
    }
    expected = {
        "files": int(stats.get("files", 0) or 0),
        "chunks": int(stats.get("chunks", 0) or 0),
        "symbols": int(stats.get("symbols", 0) or 0),
        "patch_history": int(stats.get("patch_history", 0) or 0),
    }
    mismatches = [k for k in actual if actual[k] != expected.get(k)]
    ok = not errors and not mismatches and not chunk_bad_refs and not symbol_bad_refs
    report = {
        "report_type": "CODE_INDEX_INTEGRITY_PATCH58",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "ok": ok,
        "expected": expected,
        "actual": actual,
        "mismatches": mismatches,
        "errors": errors,
        "bad_chunk_reference_count": len(chunk_bad_refs),
        "bad_symbol_reference_count": len(symbol_bad_refs),
        "duplicate_file_hash_groups": len(duplicate_file_hashes),
        "old_chroma_db": str(MEMORY_DIR / "chroma_db"),
        "code_chroma_reserved": str(CODE_CHROMA_DIR),
    }
    report_path = _code_engine_write_report("code_index_integrity", report)
    print()
    print("── Code Index Integrity ─────────────────────────────")
    print(f"  Read-only              : YES — no Chroma writes")
    print(f"  Manifest               : {data['paths']['manifest']}")
    print(f"  Files                  : expected={expected['files']} actual={actual['files']}")
    print(f"  Chunks                 : expected={expected['chunks']} actual={actual['chunks']}")
    print(f"  Symbols                : expected={expected['symbols']} actual={actual['symbols']}")
    print(f"  Patch artifacts        : expected={expected['patch_history']} actual={actual['patch_history']}")
    print(f"  Bad chunk refs         : {len(chunk_bad_refs)}")
    print(f"  Bad symbol refs        : {len(symbol_bad_refs)}")
    print(f"  Duplicate file hashes  : {len(duplicate_file_hashes)} groups")
    print(f"  Errors                 : {len(errors)}")
    for e in errors[:5]:
        print(f"    - {e}")
    print(f"  Integrity status       : {'PASS' if ok else 'REVIEW'}")
    print(f"  Report written         : {report_path}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "CODE_INDEX_INTEGRITY_SHOWN", str(report_path), f"ok={ok}", f"files={actual['files']} chunks={actual['chunks']} symbols={actual['symbols']}")


