def _symbolic_runtime_role_score(row: dict, role: dict) -> int:
    """Conservative lexical mapper from Patch 58 engine inventory rows to symbolic runtime roles."""
    hay = " ".join([
        str(row.get("engine_name", "")),
        str(row.get("engine_base", "")),
        str(row.get("root", "")),
        str(row.get("family", "")),
        " ".join(str(x) for x in row.get("sample_files", [])[:12]),
        " ".join(str(x) for x in row.get("status_tags", [])),
    ]).lower()
    score = 0
    hits = []
    for term in role.get("terms", []):
        t = str(term).lower()
        if t and t in hay:
            score += 10 if t in str(row.get("engine_base", "")).lower() or t in str(row.get("engine_name", "")).lower() else 5
            hits.append(term)
    # Respect Patch 58 canonical signal, but do not let it overpower symbolic role evidence.
    try:
        canon = int(row.get("canonical_score", 0) or 0)
    except Exception:
        canon = 0
    if score:
        score += max(-10, min(20, canon // 10))
        if "active_or_unfrozen" in row.get("status_tags", []):
            score += 5
        if "frozen" in row.get("status_tags", []):
            score -= 2
    row_base = str(row.get("engine_base", "")).lower()
    # Specific cross-links that matter to the AI.Web runtime law.
    if role.get("role_id") == "christping_correction" and "christping" in row_base:
        score += 12
    if role.get("role_id") == "spc_cold_storage" and ("symbolic_capacitor" in row_base or "cold_archive" in row_base):
        score += 12
    if role.get("role_id") == "drift_collapse" and "drift" in row_base:
        score += 12
    if role.get("role_id") == "loop_resurrection" and "resurrection" in row_base:
        score += 12
    if role.get("role_id") == "memory_persistence" and "memory_stack" in row_base:
        score += 12
    return score


def _symbolic_runtime_map_payload() -> dict:
    rows, errors = _code_engine_inventory_rows()
    role_rows = []
    assigned_roots = set()
    for role in _SYMBOLIC_RUNTIME_ROLE_DEFS:
        candidates = []
        for row in rows:
            score = _symbolic_runtime_role_score(row, role)
            if score > 0:
                slim = {
                    "engine_name": row.get("engine_name"),
                    "engine_base": row.get("engine_base"),
                    "root": row.get("root"),
                    "family": row.get("family"),
                    "canonical_score": row.get("canonical_score"),
                    "runtime_role_score": score,
                    "status_tags": row.get("status_tags", []),
                    "file_count": row.get("file_count"),
                    "symbol_count": row.get("symbol_count"),
                    "roles": row.get("roles", {}),
                    "sample_files": row.get("sample_files", [])[:8],
                }
                candidates.append(slim)
        candidates.sort(key=lambda r: (-int(r.get("runtime_role_score", 0)), -int(r.get("canonical_score", 0)), str(r.get("root", ""))))
        for c in candidates[:5]:
            assigned_roots.add(c.get("root"))
        status = "MAPPED" if candidates else ("REQUIRED_GAP" if role.get("required") else "OPTIONAL_EMPTY")
        role_rows.append({
            "role_id": role.get("role_id"),
            "title": role.get("title"),
            "description": role.get("description"),
            "required": bool(role.get("required")),
            "phases": role.get("phases", []),
            "operators": role.get("operators", []),
            "status": status,
            "candidate_count": len(candidates),
            "top_candidates": candidates[:12],
        })
    unmapped = []
    for row in rows:
        if row.get("root") not in assigned_roots:
            unmapped.append({
                "engine_name": row.get("engine_name"),
                "engine_base": row.get("engine_base"),
                "root": row.get("root"),
                "family": row.get("family"),
                "canonical_score": row.get("canonical_score"),
                "status_tags": row.get("status_tags", []),
                "file_count": row.get("file_count"),
                "symbol_count": row.get("symbol_count"),
            })
    return {
        "report_type": "SYMBOLIC_RUNTIME_MAP_PATCH59_READ_ONLY",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "implemented_destructive_action": False,
        "warning": "MAP ONLY. This command does not move, rename, delete, promote, freeze, or rewrite engine files.",
        "engine_count": len(rows),
        "symbolic_role_count": len(role_rows),
        "required_role_gaps": [r["role_id"] for r in role_rows if r.get("status") == "REQUIRED_GAP"],
        "roles": role_rows,
        "unmapped_engine_count": len(unmapped),
        "unmapped_sample": sorted(unmapped, key=lambda r: (-int(r.get("canonical_score", 0)), str(r.get("root", ""))))[:80],
        "source_inventory": "Patch 58 code engine inventory generated from code_library_v1 indexes",
        "errors": errors,
    }


def _symbolic_runtime_write_markdown(payload: dict, json_path: Path) -> Path:
    md_path = json_path.with_suffix(".md")
    lines = [
        "# Symbolic Runtime Map — Patch 59",
        "",
        f"Generated: {payload.get('timestamp')}",
        f"Read-only: {payload.get('read_only')}",
        f"Engines scanned: {payload.get('engine_count')}",
        f"Runtime roles: {payload.get('symbolic_role_count')}",
        f"Required role gaps: {', '.join(payload.get('required_role_gaps') or []) or 'none'}",
        "",
        "This is a map only. It does not clean, move, rename, promote, freeze, or delete engine files.",
        "",
    ]
    for role in payload.get("roles", []):
        lines.append(f"## {role.get('role_id')} — {role.get('title')}")
        lines.append(f"Status: {role.get('status')}  Required: {role.get('required')}  Candidates: {role.get('candidate_count')}")
        lines.append(f"Phases: {', '.join(role.get('phases', []))}")
        lines.append(f"Operators: {', '.join(role.get('operators', []))}")
        lines.append(role.get("description", ""))
        lines.append("")
        for cand in role.get("top_candidates", [])[:8]:
            lines.append(f"- {cand.get('root')} — score={cand.get('runtime_role_score')} canonical={cand.get('canonical_score')} tags={','.join(cand.get('status_tags', []))}")
        lines.append("")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return md_path


def cmd_symbolic_runtime_map(session_id: str) -> None:
    """Build a read-only RPMC/FBSC symbolic runtime map from Patch 58 engine inventory."""
    from agents.forge.memory import write_audit_entry
    payload = _symbolic_runtime_map_payload()
    report_path = _code_engine_write_report("symbolic_runtime_map", payload)
    print()
    print("── Symbolic Runtime Map ─────────────────────────────")
    print("  Mode        : MAP ONLY")
    print("  Read-only   : YES — no files changed, no Chroma writes")
    print(f"  Engines     : {payload.get('engine_count')}")
    print(f"  Roles       : {payload.get('symbolic_role_count')}")
    print(f"  Gaps        : {', '.join(payload.get('required_role_gaps') or []) or 'none'}")
    print(f"  Report path : {report_path}")
    print()
    for role in payload.get("roles", []):
        top = role.get("top_candidates", [])[:3]
        print(f"  - {role.get('role_id')}  [{role.get('status')}] candidates={role.get('candidate_count')}")
        print(f"      {role.get('title')}")
        for cand in top:
            print(f"      • {cand.get('root')} score={cand.get('runtime_role_score')} tags={','.join(cand.get('status_tags', []))}")
    if payload.get("errors"):
        print("  Index warnings:")
        for e in payload.get("errors", [])[:5]:
            print(f"    - {e}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SYMBOLIC_RUNTIME_MAP_CREATED", str(report_path), f"roles={payload.get('symbolic_role_count')}", f"gaps={len(payload.get('required_role_gaps') or [])}")


def cmd_symbolic_runtime_show(query: str, session_id: str) -> None:
    """Show one symbolic runtime role or engine mapping. Usage: symbolic-runtime-show <role|engine>"""
    from agents.forge.memory import write_audit_entry
    q = (query or "").strip().lower()
    if not q:
        print()
        print("  Usage: symbolic-runtime-show <role|engine>")
        print("  Examples:")
        print("    symbolic-runtime-show christping")
        print("    symbolic-runtime-show memory_persistence")
        print("    symbolic-runtime-show symbolic_capacitor_engine")
        print()
        return
    payload = _symbolic_runtime_map_payload()
    matches = []
    for role in payload.get("roles", []):
        role_text = " ".join([str(role.get("role_id", "")), str(role.get("title", "")), str(role.get("description", ""))]).lower()
        candidate_hits = []
        for cand in role.get("top_candidates", []):
            ctext = " ".join([str(cand.get("engine_name", "")), str(cand.get("engine_base", "")), str(cand.get("root", ""))]).lower()
            if q in ctext:
                candidate_hits.append(cand)
        if q in role_text or candidate_hits:
            matches.append((role, candidate_hits or role.get("top_candidates", [])[:8]))
    print()
    print("── Symbolic Runtime Show ────────────────────────────")
    print(f"  Query     : {query}")
    print(f"  Matches   : {len(matches)}")
    print("  Read-only : YES")
    print()
    for role, cands in matches[:12]:
        print(f"  Role      : {role.get('role_id')} — {role.get('title')}")
        print(f"  Status    : {role.get('status')}  Required={role.get('required')}  Candidates={role.get('candidate_count')}")
        print(f"  Phases    : {', '.join(role.get('phases', []))}")
        print(f"  Operators : {', '.join(role.get('operators', []))}")
        print(f"  Meaning   : {role.get('description')}")
        print("  Candidate roots:")
        for cand in cands[:10]:
            print(f"    - {cand.get('root')}  runtime_score={cand.get('runtime_role_score')} canonical={cand.get('canonical_score')} tags={','.join(cand.get('status_tags', []))}")
        print()
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SYMBOLIC_RUNTIME_SHOW", query, f"matches={len(matches)}", "read-only")


def cmd_symbolic_runtime_gaps(session_id: str) -> None:
    """Show required symbolic runtime roles with no mapped engine candidates."""
    from agents.forge.memory import write_audit_entry
    payload = _symbolic_runtime_map_payload()
    gaps = [r for r in payload.get("roles", []) if r.get("status") == "REQUIRED_GAP"]
    weak = []
    for r in payload.get("roles", []):
        tops = r.get("top_candidates", [])
        if r.get("required") and tops and int(tops[0].get("runtime_role_score", 0)) < 25:
            weak.append(r)
    report = {
        "report_type": "SYMBOLIC_RUNTIME_GAPS_PATCH59_READ_ONLY",
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "read_only": True,
        "required_gaps": gaps,
        "weak_required_mappings": weak,
        "engine_count": payload.get("engine_count"),
        "errors": payload.get("errors", []),
    }
    report_path = _code_engine_write_report("symbolic_runtime_gaps", report)
    print()
    print("── Symbolic Runtime Gaps ────────────────────────────")
    print("  Read-only       : YES — no files changed")
    print(f"  Required gaps   : {len(gaps)}")
    print(f"  Weak mappings   : {len(weak)}")
    print(f"  Report path     : {report_path}")
    print()
    if not gaps and not weak:
        print("  Result: SYMBOLIC_RUNTIME_REQUIRED_ROLES_MAPPED")
    if gaps:
        print("  Missing required roles:")
        for r in gaps:
            print(f"    - {r.get('role_id')} — {r.get('title')}")
    if weak:
        print("  Weak required mappings needing human review:")
        for r in weak:
            top = (r.get("top_candidates") or [{}])[0]
            print(f"    - {r.get('role_id')} — top={top.get('root')} score={top.get('runtime_role_score')}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SYMBOLIC_RUNTIME_GAPS_CHECKED", str(report_path), f"gaps={len(gaps)}", f"weak={len(weak)}")


