def _patch66_resolve_binding_for_command(arg: str) -> tuple[Path | None, dict | None, str]:
    path = _patch65_resolve_binding(arg or "latest")
    if not path:
        return None, None, f"Binding not found: {arg or 'latest'}"
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
    except Exception as e:
        return path, None, f"Cannot read binding: {e}"
    return path, data, ""


def _patch66_relevance_check_from_binding_path(binding_arg: str) -> dict:
    path, binding, err = _patch66_resolve_binding_for_command(binding_arg)
    if err:
        return {"ok": False, "reason": err, "binding_path": str(path or binding_arg)}
    apply_info = _patch65_read_apply_plan_fields(str(binding.get("apply_plan_path")))
    if not apply_info.get("ok"):
        return {"ok": False, "reason": apply_info.get("reason"), "binding_path": str(path), "binding": binding}
    relevance = _patch66_binding_relevance(binding, apply_info)
    return {"ok": bool(relevance.get("ok")), "reason": relevance.get("reason"), "method": relevance.get("method"), "binding_path": str(path), "binding": binding, "apply_info": apply_info, "relevance": relevance}


