    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    path = CODE_MANIFESTS_DIR / f"{ts}_{stem}.json"
    path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return path


