# ─── PATCH 71: CANONICAL ENGINE LOCKFILE DRAFT (NO ENGINE MOVES) ────────────

_PATCH71_LOCKFILE_POLICY_VERSION = "patch71_canonical_engine_lockfile_draft_v1"


def _patch71_decision_payload() -> dict:
    """Build the current Patch 69/70 decision payload without trusting model memory."""
    return _patch70_decision_payload()


def _patch71_build_lockfile_draft() -> dict:
    """Create a draft canonical lockfile payload from decision rows.

    This is NOT canonical authority. It excludes every HOLD_* decision and records those
    families separately. It does not move, delete, quarantine, promote, or edit engines.
    """
    decisions_payload = _patch71_decision_payload()
    decisions = list(decisions_payload.get("decisions", []) or [])
    included: list[dict] = []
    excluded: list[dict] = []
    errors: list[str] = []
    warnings: list[str] = []
    seen_bases: set[str] = set()

    for row in decisions:
        base = str(row.get("engine_base", "")).strip()
        decision = str(row.get("draft_decision", ""))
        keep_path = str(row.get("recommended_keep_path", "")).strip()
        variants = list(row.get("variants", []) or [])
        variant_roots = {str(v.get("root", "")) for v in variants}
        is_hold = decision.startswith("HOLD")

        if not base:
            errors.append("decision row missing engine_base")
            continue
        if base in seen_bases:
            errors.append(f"duplicate engine_base in decision draft: {base}")
        seen_bases.add(base)

        base_record = {
            "engine_base": base,
            "draft_decision": decision,
            "decision_confidence": row.get("decision_confidence"),
            "recommended_keep_path": keep_path,
            "patch68_keep_candidate": row.get("patch68_keep_candidate"),
            "variant_count": row.get("variant_count"),
            "required_human_checks": row.get("required_human_checks", []),
            "cautions": row.get("cautions", []),
            "reason": row.get("reason"),
            "source": "patch69_decision_draft",
            "status": "EXCLUDED_HOLD" if is_hold else "DRAFT_LOCK_INCLUDED",
            "no_file_action": True,
            "lockfile_written": False,
            "quarantine_written": False,
        }

        if is_hold:
            excluded.append(base_record)
            continue

        if not keep_path:
            errors.append(f"included row {base} has no recommended_keep_path")
        if keep_path and variant_roots and keep_path not in variant_roots:
            warnings.append(f"{base}: recommended_keep_path was not found among indexed variants")
            base_record["cautions"] = list(base_record.get("cautions", []) or []) + ["recommended_keep_path_not_in_variant_roots"]
        if str(row.get("decision_confidence")) == "manual":
            errors.append(f"manual-confidence row was included unexpectedly: {base}")
        if decision.startswith("DRAFT"):
            included.append(base_record)
        else:
            warnings.append(f"{base}: unknown non-HOLD decision type treated as excluded: {decision}")
            base_record["status"] = "EXCLUDED_UNKNOWN_DECISION"
            excluded.append(base_record)

    included_sorted = sorted(included, key=lambda r: str(r.get("engine_base", "")))
    excluded_sorted = sorted(excluded, key=lambda r: str(r.get("engine_base", "")))
    core_missing = sorted([b for b in _PATCH69_CORE_KEEP_BASES if b not in {r.get("engine_base") for r in included_sorted} and b not in {r.get("engine_base") for r in excluded_sorted}])
    if core_missing:
        warnings.append("core bases absent from decision payload: " + ", ".join(core_missing))

    status = "VALID_DRAFT" if not errors else "DRAFT_HAS_ERRORS"
    return {
        "report_type": "patch71_canonical_engine_lockfile_draft",
        "policy_version": _PATCH71_LOCKFILE_POLICY_VERSION,
        "timestamp": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "draft_lockfile_only",
        "read_only": True,
        "implemented_destructive_action": False,
        "engine_files_changed": False,
        "canonical_authority": False,
        "actual_lockfile_written": False,
        "draft_lockfile_written": True,
        "quarantine_written": False,
        "source_decision_report_type": decisions_payload.get("report_type"),
        "source_decision_timestamp": decisions_payload.get("timestamp"),
        "engine_count": decisions_payload.get("engine_count"),
        "decision_count": len(decisions),
        "included_count": len(included_sorted),
        "excluded_hold_count": len([r for r in excluded_sorted if r.get("status") == "EXCLUDED_HOLD"]),
        "excluded_total": len(excluded_sorted),
        "status": status,
        "errors": errors,
        "warnings": warnings,
        "policy": {
            "rule": "Only DRAFT_* decisions enter this draft. HOLD_* decisions are excluded and must be architect-reviewed before any future lockfile authority.",
            "forbidden": ["move", "delete", "rename", "quarantine", "promote", "edit_engine_files", "make_authoritative_lockfile"],
            "next_phase": "human review of draft lockfile before any canonical authority or quarantine plan",
        },
        "lockfile_entries": included_sorted,
        "excluded_holds": excluded_sorted,
    }


def _patch71_write_draft(payload: dict, stem: str = "engine_canonical_lockfile_draft") -> Path:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    path = CODE_MANIFESTS_DIR / f"{ts}_{stem}.json"
    path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    return path


def _patch71_latest_lockfile_draft() -> Path | None:
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    rows = sorted(CODE_MANIFESTS_DIR.glob("*engine_canonical_lockfile_draft.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    return rows[0] if rows else None


def _patch71_load_or_build_lockfile() -> dict:
    latest = _patch71_latest_lockfile_draft()
    if latest:
        try:
            return json.loads(latest.read_text(encoding="utf-8"))
        except Exception:
            pass
    return _patch71_build_lockfile_draft()


def _patch71_validation(payload: dict) -> dict:
    errors = list(payload.get("errors", []) or [])
    warnings = list(payload.get("warnings", []) or [])
    entries = list(payload.get("lockfile_entries", []) or [])
    holds = list(payload.get("excluded_holds", []) or [])
    entry_bases = [str(e.get("engine_base", "")) for e in entries]
    hold_bases = [str(h.get("engine_base", "")) for h in holds]

    if payload.get("implemented_destructive_action"):
        errors.append("payload claims destructive action was implemented")
    if payload.get("engine_files_changed"):
        errors.append("payload claims engine files changed")
    if payload.get("canonical_authority"):
        errors.append("draft payload incorrectly claims canonical authority")
    if payload.get("quarantine_written"):
        errors.append("draft payload incorrectly claims quarantine_written")

    for e in entries:
        decision = str(e.get("draft_decision", ""))
        if decision.startswith("HOLD"):
            errors.append(f"HOLD decision included in lockfile_entries: {e.get('engine_base')}")
        if not str(e.get("recommended_keep_path", "")).strip():
            errors.append(f"entry missing recommended_keep_path: {e.get('engine_base')}")
        if e.get("decision_confidence") == "manual":
            errors.append(f"manual confidence entry included: {e.get('engine_base')}")

    dupes = sorted({b for b in entry_bases if entry_bases.count(b) > 1})
    for b in dupes:
        errors.append(f"duplicate included engine_base: {b}")
    overlap = sorted(set(entry_bases) & set(hold_bases))
    for b in overlap:
        errors.append(f"engine_base appears in both included and excluded_holds: {b}")

    required_counts_ok = (int(payload.get("decision_count", 0) or 0) == len(entries) + len(holds))
    if not required_counts_ok:
        warnings.append("decision_count does not equal included + excluded totals")

    return {
        "status": "PASS" if not errors else "FAIL",
        "errors": errors,
        "warnings": warnings,
        "included_count": len(entries),
        "excluded_hold_count": len([h for h in holds if h.get("status") == "EXCLUDED_HOLD"]),
        "excluded_total": len(holds),
        "decision_count": payload.get("decision_count"),
    }


