def cmd_engine_lockfile_draft(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    payload = _patch71_build_lockfile_draft()
    path = _patch71_write_draft(payload)
    validation = _patch71_validation(payload)
    print()
    print("── Engine Lockfile Draft ────────────────────────────")
    print("  Mode        : DRAFT LOCKFILE ONLY")
    print("  Read-only   : YES — no engine files changed")
    print("  Authority   : NO — not a final canonical lockfile")
    print(f"  Decisions   : {payload.get('decision_count')}")
    print(f"  Included    : {payload.get('included_count')}")
    print(f"  Excluded    : {payload.get('excluded_total')}  holds={payload.get('excluded_hold_count')}")
    print(f"  Status      : {payload.get('status')}  validation={validation.get('status')}")
    print(f"  Draft path  : {path}")
    print("  Sample included entries:")
    for row in payload.get("lockfile_entries", [])[:12]:
        print(f"    - {row.get('engine_base')} -> {row.get('recommended_keep_path')}  ({row.get('decision_confidence')})")
    if len(payload.get("lockfile_entries", [])) > 12:
        print(f"    ... {len(payload.get('lockfile_entries', [])) - 12} more included entries")
    print("  Held/excluded families:")
    for row in payload.get("excluded_holds", [])[:12]:
        print(f"    - {row.get('engine_base')} [{row.get('draft_decision')}]")
    if validation.get("errors"):
        print("  Errors:")
        for e in validation.get("errors", [])[:8]:
            print(f"    - {e}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_LOCKFILE_DRAFT_CREATED", str(path), f"included={payload.get('included_count')} excluded={payload.get('excluded_total')}", f"validation={validation.get('status')}")


