def cmd_engine_lockfile_export(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    payload = _patch71_load_or_build_lockfile()
    CODE_MANIFESTS_DIR.mkdir(parents=True, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y-%m-%d_%H%M%S")
    json_path = CODE_MANIFESTS_DIR / f"{ts}_engine_canonical_lockfile_draft_export.json"
    md_path = CODE_MANIFESTS_DIR / f"{ts}_engine_canonical_lockfile_draft_export.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = []
    lines.append("# Canonical Engine Lockfile Draft — Patch 71")
    lines.append("")
    lines.append("This is a draft review artifact only. It is not canonical authority and does not move, delete, quarantine, or edit engine files.")
    lines.append("")
    lines.append(f"- Policy version: `{payload.get('policy_version')}`")
    lines.append(f"- Included entries: **{payload.get('included_count')}**")
    lines.append(f"- Excluded/held entries: **{payload.get('excluded_total')}**")
    lines.append(f"- Status: **{payload.get('status')}**")
    lines.append("")
    lines.append("## Included Draft Entries")
    for row in payload.get("lockfile_entries", []):
        lines.append(f"- **{row.get('engine_base')}** → `{row.get('recommended_keep_path')}` ({row.get('decision_confidence')})")
