def cmd_engine_review_batch_approve_core(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    ledger, path, err = _patch73_ledger_or_create()
    print()
    print("── Engine Review Batch Approve Core ────────────────")
    print("  Mode        : LEDGER WRITE ONLY — no engine files changed")
    print("  Authority   : NO — approvals are candidates for a future lockfile only")
    print(f"  Ledger      : {path}")
    if err:
        print(f"  Status      : {err}")
        print("──────────────────────────────────────────────────────")
        print()
        return
    changed = []
    skipped = []
    for row in _patch73_core_rows(ledger):
        base = row.get("engine_base")
        status = str(row.get("review_status", "PENDING_REVIEW")).upper()
        if row.get("is_hold_family"):
            skipped.append((base, "hold_family"))
            continue
        if status == "REJECTED":
            skipped.append((base, "rejected"))
            continue
        if status == "APPROVED" and row.get("future_lockfile_eligible"):
            skipped.append((base, "already_approved"))
            continue
        _patch72_mark_row(row, "approved", "Patch 73 batch-approved core runtime candidate; still not canonical authority")
        changed.append(base)
    _patch72_save_ledger(ledger)
    counts = _patch73_batch_counts(ledger)
    print(f"  Core rows   : {counts['core_total']}")
    print(f"  Approved now: {len(changed)}")
    print(f"  Skipped     : {len(skipped)}")
    if changed:
        print("  Approved bases:")
        for base in changed[:20]:
            print(f"    - {base}")
        if len(changed) > 20:
            print(f"    ... {len(changed) - 20} more")
    if skipped:
        print("  Skipped bases:")
        for base, reason in skipped[:12]:
            print(f"    - {base} ({reason})")
        if len(skipped) > 12:
            print(f"    ... {len(skipped) - 12} more")
    print(f"  Eligible candidates for future approved lockfile: {counts['eligible_candidates']}")
    print("  Result      : ENGINE_REVIEW_BATCH_CORE_APPROVED")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_REVIEW_BATCH_CORE_APPROVED", str(path), f"changed={len(changed)} skipped={len(skipped)}", "authority=no")


