def _llm_tool_policy_payload() -> dict:
    return {
        "schema_version": LLM_TOOL_GATEWAY_SCHEMA_VERSION,
        "policy": "Patch 76 LLM Tool Gateway Policy",
        "mode": LLM_TOOL_GATEWAY_MODE,
        "purpose": "Let the LLM request Forge tools through a permission wall while Forge records the request and refuses unsafe access.",
        "execution_performed_by_gateway": False,
        "initial_authority": "request receipts and safety classification only; no nested command execution yet",
        "allowed_tool_count": len(LLM_TOOL_GATEWAY_ALLOWED),
        "allowed_tools": sorted(LLM_TOOL_GATEWAY_ALLOWED.keys()),
        "forbidden_exact": sorted(LLM_TOOL_GATEWAY_FORBIDDEN_EXACT),
        "forbidden_patterns": LLM_TOOL_GATEWAY_FORBIDDEN_PATTERNS,
        "forbidden": [
            "raw shell access",
            "write tools",
            "execute tools",
            "patch apply",
            "rollback restore",
            "delete/quarantine/cleanup",
            "Chroma/vector writes",
            "pip/npm/network/sudo commands",
            "unscoped file access",
            "secret or credential paths",
            "hidden chain-of-thought storage",
        ],
        "core_rule": "The LLM may request. Forge checks and records. Nic approves future actions. No write or execute authority is granted by this gateway patch.",
    }


def _llm_tool_registry_metadata(tool_name: str) -> dict:
    reg_path = CONFIG_DIR / "tool_registry.json"
    key = (tool_name or "").strip().replace("-", "_")
    try:
        data = json.loads(reg_path.read_text(encoding="utf-8"))
        tools = data.get("tools", {})
        if isinstance(tools, dict):
            return tools.get(key, {}) or {}
    except Exception:
        pass
    return {}


def _llm_tool_contains_forbidden(raw: str) -> list[str]:
    low = f" {str(raw or '').lower()} "
    hits = []
    for pat in LLM_TOOL_GATEWAY_FORBIDDEN_PATTERNS:
        if pat.lower() in low:
            hits.append(pat)
    return hits


def _llm_tool_extract_paths(args: str) -> list[str]:
    text = str(args or "")
    # Conservative path scanner for absolute paths and home paths. This is not execution parsing.
    matches = re.findall(r"(?<![A-Za-z0-9_])(~?/[^\s'\";|&<>`]+)", text)
    return matches[:20]


def _llm_tool_path_safety(args: str) -> tuple[bool, list[str]]:
    reasons = []
    paths = _llm_tool_extract_paths(args)
    if not paths:
        return True, reasons
    bases = []
    try:
        bases.extend(get_session_paths() or [])
    except Exception:
        pass
    try:
        bases.extend(get_approved_paths() or [])
    except Exception:
        pass
    bases.append(str(FORGE_ROOT))
    safe_bases = []
    for base in bases:
        try:
            safe_bases.append(Path(base).expanduser().resolve())
        except Exception:
            continue
    for raw in paths:
        try:
            p = Path(raw).expanduser().resolve()
        except Exception:
            reasons.append(f"unresolvable path: {raw}")
            continue
        lowered = str(p).lower()
        if any(x in lowered for x in ["/.ssh", "/.gnupg", "/.aws", "/.config", "/.env", "id_rsa", "id_ed25519"]):
            reasons.append(f"sensitive path refused: {raw}")
            continue
        allowed = False
        for base in safe_bases:
            try:
                p.relative_to(base)
                allowed = True
                break
            except Exception:
                continue
        if not allowed:
            reasons.append(f"path outside Forge/approved scope: {raw}")
    return len(reasons) == 0, reasons


def _llm_tool_split_request(raw_request: str) -> tuple[str, str]:
    raw = (raw_request or "").strip()
    if not raw:
        return "", ""
    parts = raw.split(maxsplit=1)
    tool = parts[0].strip()
    args = parts[1].strip() if len(parts) > 1 else ""
    return tool, args


def _llm_tool_check_payload(raw_request: str) -> dict:
    tool, args = _llm_tool_split_request(raw_request)
    normalized_tool = tool.strip()
    reasons = []
    status = "REFUSED"
    allowed = False

    if not normalized_tool:
        reasons.append("missing tool name")
    if normalized_tool in LLM_TOOL_GATEWAY_FORBIDDEN_EXACT:
        reasons.append("tool is explicitly forbidden in Patch 76 gateway")
    if normalized_tool not in LLM_TOOL_GATEWAY_ALLOWED:
        reasons.append("tool is not in the Patch 76 read-only gateway allowlist")

    forbidden_hits = _llm_tool_contains_forbidden(f"{normalized_tool} {args}")
    if forbidden_hits:
        reasons.append("forbidden shell/sensitive pattern(s): " + ", ".join(sorted(set(forbidden_hits))))

    path_ok, path_reasons = _llm_tool_path_safety(args)
    if not path_ok:
        reasons.extend(path_reasons)

    meta = _llm_tool_registry_metadata(normalized_tool)
    if meta:
        if meta.get("writes") is True:
            reasons.append("tool registry marks this tool as writes=True")
        if meta.get("executes") is True:
            reasons.append("tool registry marks this tool as executes=True")

    if not reasons and normalized_tool in LLM_TOOL_GATEWAY_ALLOWED:
        allowed = True
        status = "ALLOWED_READ_ONLY_REQUEST"
        reasons.append("request is read-only allowlisted; Patch 76 records a receipt but does not execute the tool")

    return {
        "schema_version": LLM_TOOL_GATEWAY_SCHEMA_VERSION,
        "request_type": "LLM_TOOL_GATEWAY_CHECK_V1",
        "timestamp": _llm_memory_iso(),
        "mode": LLM_TOOL_GATEWAY_MODE,
        "raw_request": raw_request or "",
        "tool_name": normalized_tool,
        "tool_args": args,
        "status": status,
        "allowed": allowed,
        "reasons": reasons,
        "registry_metadata": meta,
        "execution_performed": False,
        "project_files_changed": False,
        "hidden_chain_of_thought_stored": False,
        "next_step": "If allowed, Nic or a future gateway execution patch can decide whether to run the equivalent Forge command explicitly.",
    }


def _llm_tool_latest_request() -> tuple[Path | None, dict | None, str]:
    idx = LLM_MEMORY_INDEXES_DIR / "latest_tool_request.json"
    if idx.exists():
        try:
            data = json.loads(idx.read_text(encoding="utf-8"))
            path = Path(data.get("latest_request_path", ""))
            if path.exists() and path.is_file():
                return path, json.loads(path.read_text(encoding="utf-8")), ""
        except Exception as e:
            return None, None, f"latest tool request index unreadable: {e}"
    if not LLM_MEMORY_TOOL_REQUESTS_DIR.exists():
        return None, None, "no tool request receipts found"
    rows = sorted(LLM_MEMORY_TOOL_REQUESTS_DIR.glob("llm_tool_request_*.json"), key=lambda p: p.stat().st_mtime, reverse=True)
    if not rows:
        return None, None, "no tool request receipts found"
    try:
        return rows[0], json.loads(rows[0].read_text(encoding="utf-8")), ""
    except Exception as e:
        return None, None, f"tool request receipt unreadable: {e}"


def _llm_tool_resolve_report(arg: str) -> tuple[Path | None, dict | None, str]:
    raw = (arg or "latest").strip()
    if not raw or raw == "latest":
        return _llm_tool_latest_request()
    candidate = Path(os.path.expanduser(raw))
    if candidate.is_absolute():
        try:
            candidate.resolve().relative_to(LLM_MEMORY_TOOL_REQUESTS_DIR.resolve())
        except Exception:
            return None, None, f"Tool request path must be inside {LLM_MEMORY_TOOL_REQUESTS_DIR}; got {candidate}"
        if candidate.exists() and candidate.is_file():
            try:
                return candidate, json.loads(candidate.read_text(encoding="utf-8")), ""
            except Exception as e:
                return None, None, f"Tool request receipt unreadable: {e}"
    if not LLM_MEMORY_TOOL_REQUESTS_DIR.exists():
        return None, None, "no tool request receipts found"
    for path in sorted(LLM_MEMORY_TOOL_REQUESTS_DIR.glob("*.json"), key=lambda p: p.stat().st_mtime, reverse=True):
        if path.stem == raw or raw in path.name:
            try:
                return path, json.loads(path.read_text(encoding="utf-8")), ""
            except Exception as e:
                return None, None, f"Tool request receipt unreadable: {e}"
    return None, None, f"No tool request receipt matched: {raw}"


