def cmd_llm_tool_request(raw_request: str, session_id: str) -> None:
    """Write an audited LLM tool request receipt. Usage: llm-tool-request <tool> [args]"""
    from agents.forge.memory import write_audit_entry
    _llm_memory_ensure_dirs()
    payload = _llm_tool_check_payload(raw_request)
    receipt_id = f"llm_tool_request_{_llm_memory_ts()}_{_llm_memory_sha16((raw_request or '') + session_id)}"
    path = LLM_MEMORY_TOOL_REQUESTS_DIR / f"{receipt_id}.json"
    payload.update({
        "receipt_type": "LLM_TOOL_REQUEST_RECEIPT_V1",
        "receipt_id": receipt_id,
        "session_id": session_id,
        "receipt_path": str(path),
        "user_approved_execution": False,
        "user_approved_project_write": False,
    })
    _llm_memory_write_json(path, payload)
    _llm_memory_write_json(LLM_MEMORY_INDEXES_DIR / "latest_tool_request.json", {
        "schema_version": LLM_TOOL_GATEWAY_SCHEMA_VERSION,
        "updated_at": _llm_memory_iso(),
        "latest_request_id": receipt_id,
        "latest_request_path": str(path),
        "latest_status": payload["status"],
        "latest_tool_name": payload.get("tool_name"),
    })
    _llm_memory_append_session_line(session_id, {
        "timestamp": payload["timestamp"],
        "receipt_id": receipt_id,
        "receipt_type": payload["receipt_type"],
        "summary": f"Tool request {payload.get('tool_name')}: {payload['status']}",
        "receipt_path": str(path),
    })
    _llm_memory_update_latest(payload)
    write_audit_entry(session_id, "LLM_TOOL_REQUEST_WRITTEN", str(path), payload["status"], "execution_performed=NO")
    print()
    print("── LLM Tool Request Receipt Written ─────────────────")
    print("  Receipt       :", receipt_id)
    print("  Tool          :", payload.get("tool_name") or "(missing)")
    print("  Status        :", payload["status"])
    print("  Path          :", path)
    print("  Executes      : NO")
    print("  Project writes: NO")
    print("  Hidden CoT    : NOT STORED")
    print()
    print("  Reasons:")
    for reason in payload["reasons"]:
        print("   -", reason)
    print("──────────────────────────────────────────────────────")
    print()


