CODE_RELATIONSHIP_SCHEMA_VERSION = "code_relationship_v1_patch79"
CODE_RELATIONSHIP_EXPORT_PREFIX = "code_relationship_intelligence_report"


def _patch79_policy_payload() -> dict:
    return {
        "schema_version": CODE_RELATIONSHIP_SCHEMA_VERSION,
        "patch": 79,
        "mode": "READ_ONLY_CODE_RELATIONSHIP_INTELLIGENCE",
        "purpose": "Map an engine family to indexed files, symbols, tests, runtime roles, variants, and risk neighbors before any final lockfile authority.",
        "writes": "code-relationship-export writes JSON/Markdown reports only under Forge-owned memory/code_library_v1/manifests.",
        "authority": {
            "final_lockfile_authority": False,
            "engine_file_write_authority": False,
            "quarantine_authority": False,
            "delete_authority": False,
            "shell_access": False,
            "chroma_write_authority": False,
        },
        "forbidden": [
            "no engine moves",
            "no engine deletion",
            "no quarantine",
            "no final authority",
            "no shell execution",
            "no Chroma writes",
            "no hidden chain-of-thought storage",
        ],
        "core_rule": "The LLM may explain relationships. Forge must verify relationships from disk-backed indexes, manifests, and receipts.",
    }


def _patch79_norm_base(engine_base: str) -> str:
    base = str(engine_base or "").strip().replace("-", "_").lower()
    base = re.sub(r"[^a-z0-9_]+", "_", base)
    base = re.sub(r"__+", "_", base).strip("_")
    return base


def _patch79_term_set(engine_base: str, readiness_row: dict | None = None, roles: list[dict] | None = None) -> list[str]:
    base = _patch79_norm_base(engine_base)
    terms = {base}
    if base.endswith("_engine"):
        terms.add(base[:-7])
    for part in base.split("_"):
        if len(part) >= 4:
            terms.add(part)
    if readiness_row:
        for key in ("canonical_path_candidate", "plain_english_purpose", "review_note", "draft_decision"):
            for tok in re.findall(r"[A-Za-z0-9_]+", str(readiness_row.get(key, "")).lower()):
                if len(tok) >= 5 and tok not in {"engine", "candidate", "authority", "review", "before", "after", "plain", "english"}:
                    terms.add(tok)
    for role in roles or []:
        for key in ("role_id", "title", "description"):
            for tok in re.findall(r"[A-Za-z0-9_]+", str(role.get(key, "")).lower()):
                if len(tok) >= 5 and tok not in {"engine", "runtime", "symbolic", "candidate"}:
                    terms.add(tok)
    return sorted(t for t in terms if t)


def _patch79_readiness_map() -> dict[str, dict]:
    try:
        report = _patch78_build_report()
        return {str(r.get("engine_base", "")).lower(): r for r in report.get("candidate_rows", [])}
    except Exception:
        return {}


def _patch79_engine_variants(engine_base: str) -> tuple[list[dict], list[str]]:
    base = _patch79_norm_base(engine_base)
    rows, errors = _code_engine_inventory_rows()
    matches = [r for r in rows if str(r.get("engine_base", "")).lower() == base]
    if not matches:
        # Fallback fuzzy path/name match, read-only only.
        matches = [r for r in rows if base in " ".join([str(r.get("engine_name", "")), str(r.get("root", ""))]).lower()]
    matches.sort(key=lambda r: (-int(r.get("canonical_score", 0) or 0), str(r.get("root", ""))))
    return matches, errors


def _patch79_file_category(rel: str, role: str, suffix: str) -> str:
    low = str(rel or "").lower()
    r = str(role or "").lower()
    s = str(suffix or "").lower()
    if "test" in low or r == "test_file":
        return "test_or_validation"
    if "runtime_wrappers/" in low or "wrapper" in low or "launcher" in low:
        return "runtime_wrapper"
    if "/config/" in low or low.endswith(".json") or s == ".json":
        return "config_or_manifest"
    if "/docs/" in low or low.endswith(".md") or low.endswith(".txt"):
        return "documentation_or_notes"
    if "/engines/" in low:
        return "engine_source"
    if "/agents/" in low:
        return "agent_source"
    return "indexed_source"


def _patch79_score_file(file_row: dict, engine_base: str, terms: list[str], variants: list[dict], readiness_row: dict | None) -> tuple[int, list[str]]:
    rel = str(file_row.get("relative_path", ""))
    low = rel.lower()
    base = _patch79_norm_base(engine_base)
    reasons: list[str] = []
    score = 0
    if base and base in low:
        score += 70
        reasons.append("engine_base_in_path")
    for v in variants:
        root = str(v.get("root", "")).lower()
        if root and (low == root or low.startswith(root.rstrip("/") + "/")):
            score += 120
            reasons.append("inside_engine_variant_root")
            break
    cand = str((readiness_row or {}).get("canonical_path_candidate", "")).lower()
    if cand and (low == cand or low.startswith(cand.rstrip("/") + "/")):
        score += 160
        reasons.append("inside_approved_candidate_path")
    term_hits = [t for t in terms if len(t) >= 4 and t in low]
    if term_hits:
        score += min(60, 8 * len(set(term_hits)))
        reasons.append("term_hits=" + ",".join(sorted(set(term_hits))[:8]))
    category = _patch79_file_category(rel, file_row.get("file_role"), file_row.get("suffix"))
    if score and category == "test_or_validation":
        score += 25
        reasons.append("test_or_validation_neighbor")
    if score and category == "runtime_wrapper":
        score += 20
        reasons.append("runtime_wrapper_neighbor")
    if score and category == "config_or_manifest":
        score += 15
        reasons.append("config_or_manifest_neighbor")
    return score, reasons


def _patch79_related_file_rows(engine_base: str, limit: int = 80) -> tuple[list[dict], dict, list[str]]:
    base = _patch79_norm_base(engine_base)
    data, errors = _code_load_current_indexes(load_chunks=True)
    readiness = _patch79_readiness_map().get(base)
    variants, inv_errors = _patch79_engine_variants(base)
    errors.extend(inv_errors)
    roles = _patch77_runtime_roles_for(base, str((readiness or {}).get("canonical_path_candidate", "")))
    terms = _patch79_term_set(base, readiness, roles)
    ranked = []
    for f in data.get("files", []):
        score, reasons = _patch79_score_file(f, base, terms, variants, readiness)
        if score > 0:
            rel = str(f.get("relative_path", ""))
            ranked.append({
                "relative_path": rel,
                "absolute_path": f.get("absolute_path"),
                "file_role": f.get("file_role"),
                "suffix": f.get("suffix"),
                "line_count": f.get("line_count"),
                "sha256_16": f.get("sha256_16"),
                "category": _patch79_file_category(rel, f.get("file_role"), f.get("suffix")),
                "relationship_score": score,
                "relationship_reasons": reasons[:10],
            })
    ranked.sort(key=lambda r: (-int(r.get("relationship_score", 0)), str(r.get("category", "")), str(r.get("relative_path", ""))))

    # Symbol matches remain separate so Nic can see code-level entry points without opening raw files first.
    symbol_rows = []
    for s in data.get("symbols", []):
        blob = " ".join([str(s.get("symbol", "")), str(s.get("relative_path", "")), str(s.get("kind", ""))]).lower()
        hits = [t for t in terms if len(t) >= 4 and t in blob]
        if hits:
            symbol_rows.append({
                "kind": s.get("kind"),
                "symbol": s.get("symbol"),
                "relative_path": s.get("relative_path"),
                "line": s.get("line"),
                "hits": sorted(set(hits))[:8],
            })
    symbol_rows.sort(key=lambda r: (str(r.get("relative_path", "")), int(r.get("line", 0) or 0), str(r.get("symbol", ""))))

    # Patch/history neighbors are advisory only.
    patch_rows = []
    for p in data.get("patch_history", []):
        blob = " ".join([str(p.get("relative_path", "")), str(p.get("filename", "")), str(p.get("artifact_area", ""))]).lower()
        hits = [t for t in terms if len(t) >= 4 and t in blob]
        if hits:
            patch_rows.append({
                "relative_path": p.get("relative_path"),
                "artifact_area": p.get("artifact_area"),
                "filename": p.get("filename"),
                "sha256_16": p.get("sha256_16"),
                "hits": sorted(set(hits))[:8],
            })
    patch_rows.sort(key=lambda r: (str(r.get("artifact_area", "")), str(r.get("relative_path", ""))))

    meta = {
        "engine_base": base,
        "terms": terms,
        "readiness_row_found": bool(readiness),
        "readiness_status": (readiness or {}).get("readiness_status"),
        "candidate_path": (readiness or {}).get("canonical_path_candidate"),
        "variant_count": len(variants),
        "variants": variants[:20],
        "runtime_roles": roles[:12],
        "symbol_matches": symbol_rows[:60],
        "patch_history_neighbors": patch_rows[:40],
        "index_stats": (data.get("manifest") or {}).get("stats", {}),
    }
    return ranked[:limit], meta, errors


def _patch79_risk_notes(related_files: list[dict], meta: dict) -> list[str]:
    notes = []
    categories = {}
    for row in related_files:
        categories[row.get("category", "unknown")] = categories.get(row.get("category", "unknown"), 0) + 1
    if int(meta.get("variant_count", 0) or 0) > 1:
        notes.append(f"multiple variants detected: {meta.get('variant_count')}; compare before final authority")
    if categories.get("test_or_validation", 0) == 0:
        notes.append("no related test/validation file found in indexed code; test coverage may be missing or not indexed")
    else:
        notes.append(f"related test/validation files found: {categories.get('test_or_validation', 0)}")
    if categories.get("runtime_wrapper", 0):
        notes.append(f"runtime wrapper neighbors found: {categories.get('runtime_wrapper', 0)}")
    if categories.get("config_or_manifest", 0):
        notes.append(f"config/manifest neighbors found: {categories.get('config_or_manifest', 0)}")
    if not meta.get("readiness_row_found"):
        notes.append("engine is not in the approved readiness candidate list; treat as pending/held/excluded until reviewed")
    else:
        notes.append("engine appears in the approved candidate readiness report, but this is not final authority")
    return notes


def _patch79_relationship_payload(engine_base: str) -> dict:
    files, meta, errors = _patch79_related_file_rows(engine_base, limit=100)
    categories = {}
    for row in files:
        categories[row.get("category", "unknown")] = categories.get(row.get("category", "unknown"), 0) + 1
    return {
        "schema_version": CODE_RELATIONSHIP_SCHEMA_VERSION,
        "report_type": "CODE_RELATIONSHIP_INTELLIGENCE_SINGLE_ENGINE_V1",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "READ_ONLY_RELATIONSHIP_MAP_ONLY",
        "engine_base": meta.get("engine_base"),
        "authority": _patch79_policy_payload()["authority"],
        "readiness": {
            "row_found": meta.get("readiness_row_found"),
            "status": meta.get("readiness_status"),
            "candidate_path": meta.get("candidate_path"),
        },
        "counts": {
            "related_files": len(files),
            "symbols": len(meta.get("symbol_matches", [])),
            "patch_history_neighbors": len(meta.get("patch_history_neighbors", [])),
            "variants": meta.get("variant_count"),
            "runtime_roles": len(meta.get("runtime_roles", [])),
        },
        "category_counts": categories,
        "risk_notes": _patch79_risk_notes(files, meta),
        "terms_used": meta.get("terms", []),
        "runtime_roles": meta.get("runtime_roles", []),
        "variants": meta.get("variants", []),
        "related_files": files,
        "symbol_matches": meta.get("symbol_matches", []),
        "patch_history_neighbors": meta.get("patch_history_neighbors", []),
        "index_stats": meta.get("index_stats", {}),
        "errors": errors,
        "recommended_next_step": "Use this relationship map to decide what files/tests/wrappers must be reviewed before any future final lockfile authority.",
        "suggested_next_command": f"code-related-files {meta.get('engine_base')}",
    }


