    print(f"  Engine       : {payload.get('engine_base')}")
    read = payload.get("readiness", {})
    print(f"  Readiness    : row_found={read.get('row_found')} status={read.get('status')}")
    print(f"  Candidate    : {read.get('candidate_path') or '(none)'}")
    counts = payload.get("counts", {})
    print(f"  Related files: {counts.get('related_files')}  symbols={counts.get('symbols')}  variants={counts.get('variants')}  roles={counts.get('runtime_roles')}")
    print("  Category counts:")
    for k, v in sorted(payload.get("category_counts", {}).items()):
        print(f"    - {k}: {v}")
    print("  Risk notes:")
    for note in payload.get("risk_notes", [])[:12]:
        print(f"    - {note}")
    print("  Authority    : NO final lockfile, NO engine file changes, NO quarantine")


