SNAPSHOT_MANIFEST_POLICY_VERSION = "patch81_snapshot_manifest_dry_run_v1"
SNAPSHOT_MANIFEST_MAX_FILES_PER_ROOT = 3500
SNAPSHOT_MANIFEST_MAX_FILE_BYTES = 5 * 1024 * 1024


