def cmd_snapshot_readiness_export(session_id: str) -> None:
    """Export snapshot readiness receipt index. Usage: snapshot-readiness-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_READINESS_DIR.mkdir(parents=True, exist_ok=True)
    rows = []
    for p in _snapshot_readiness_paths():
        report = _snapshot_readiness_load(p) or {}
        rows.append({
            "path": str(p),
            "created_at": report.get("created_at"),
            "status": report.get("status"),
            "eligible": report.get("future_snapshot_create_proposal_eligible"),
            "blockers": len(report.get("blockers", []) or []),
            "warnings": len(report.get("warnings", []) or []),
            "manifest": (report.get("sources") or {}).get("snapshot_manifest"),
        })
    payload = {
        "schema_version": SNAPSHOT_READINESS_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_READINESS_EXPORT_V1_PATCH82",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_SNAPSHOT_CREATE_NO_RESTORE",
        "authority": _snapshot_readiness_authority(),
        "count": len(rows),
        "readiness_reports": rows,
    }
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_READINESS_DIR / f"{ts}_{SNAPSHOT_READINESS_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_READINESS_DIR / f"{ts}_{SNAPSHOT_READINESS_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 82 Snapshot Readiness Export",
        "",
        "Mode: EXPORT ONLY. No snapshot was created. No restore authority exists.",
        f"Generated: `{payload.get('created_at')}`",
        f"Readiness reports: **{len(rows)}**",
        "",
    ]
    for row in rows[:100]:
        lines.append(f"- `{row.get('created_at')}` status=`{row.get('status')}` eligible=`{row.get('eligible')}` blockers=`{row.get('blockers')}` warnings=`{row.get('warnings')}` path=`{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Snapshot Readiness Export ────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  JSON      :", json_path)
    print("  Markdown  :", md_path)
    print("  Reports   :", len(rows))
    print("  Authority : NO create, NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_READINESS_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(rows)}")


# ─── PATCH 83 — SNAPSHOT CREATE (NO RESTORE AUTHORITY) ──────────────────────

SNAPSHOT_CREATE_POLICY_VERSION = "patch83_snapshot_create_no_restore_v1"
SNAPSHOT_CREATE_MAX_FILES = 1500


def _snapshot_create_authority() -> dict:
    return {
        "snapshot_create_authority": True,
        "restore_authority": False,
        "shadow_restore_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_access": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_archive_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_CREATE_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_CREATE_POLICY_VERSION,
        "policy": "Patch 83 Snapshot Create, No Restore Authority",
        "mode": "SNAPSHOT_CREATE_ONLY_NO_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Create a Forge-owned snapshot archive from the latest validated dry-run manifest and readiness receipt, while keeping restore and project-write authority locked off.",
        "authority": _snapshot_create_authority(),
        "allowed_writes": [
            "Forge-owned snapshot archive directories under /home/nic/forge/memory/snapshots_v1/",
            "Forge-owned snapshot create JSON/Markdown receipts",
            "Forge audit entries describing snapshot create/show/verify/export commands",
        ],
        "forbidden": [
            "restoring files",
            "shadow restore",
            "writing to /home/nic/aiweb or any approved project path",
            "editing, deleting, moving, quarantining, or promoting engines",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
            "writing to Chroma or old vector DBs",
            "granting final lockfile authority",
        ],
        "required_inputs": [
            "latest snapshot manifest dry-run receipt",
            "latest snapshot readiness receipt with zero blockers",
            "current files must match manifest hashes except expected volatile audit-log drift",
        ],
    }


def _snapshot_create_paths() -> list[Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_ARCHIVES_DIR.glob(f"*_{SNAPSHOT_CREATE_PREFIX}.json"), reverse=True)


def _snapshot_create_latest_path() -> Path | None:
    paths = _snapshot_create_paths()
    return paths[0] if paths else None


def _snapshot_create_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_create_safe_name(row: dict, idx: int) -> str:
    label = str(row.get("label") or row.get("relative_path") or row.get("root_label") or "file")
    safe = re.sub(r"[^A-Za-z0-9._-]+", "_", label).strip("._-")[:80] or "file"
    suffix = Path(str(row.get("path") or "")).suffix
    sha16 = str(row.get("sha256_16") or row.get("sha256") or "nohash")[:16]
    if suffix and not safe.endswith(suffix):
        safe = f"{safe}{suffix}"
    return f"{idx:04d}_{sha16}_{safe}"


def _snapshot_create_collect_rows(manifest: dict) -> list[dict]:
    rows = []
    seen_paths: set[str] = set()
    for row in _snapshot_readiness_manifest_rows(manifest):
        if not isinstance(row, dict) or not row.get("included"):
            continue
        path = str(row.get("path") or "").strip()
        if not path or path in seen_paths:
            continue
        seen_paths.add(path)
        rows.append(dict(row))
        if len(rows) >= SNAPSHOT_CREATE_MAX_FILES:
            break
    return rows


def _snapshot_create_preflight(manifest: dict, readiness: dict) -> tuple[list[dict], list[str], list[str]]:
    blockers: list[str] = []
    warnings: list[str] = []
    rows = _snapshot_create_collect_rows(manifest)
    if not rows:
        blockers.append("No included file rows found in latest snapshot manifest.")
    if not isinstance(readiness, dict):
        blockers.append("Latest readiness receipt is unavailable or invalid.")
    else:
        if readiness.get("future_snapshot_create_proposal_eligible") is not True:
            blockers.append("Latest readiness receipt does not mark future snapshot-create proposal eligible.")
        if readiness.get("blockers"):
            blockers.append(f"Latest readiness receipt has blockers: {len(readiness.get('blockers') or [])}")
    if len(rows) >= SNAPSHOT_CREATE_MAX_FILES:
        warnings.append(f"Snapshot file list reached safety cap: {SNAPSHOT_CREATE_MAX_FILES}")
    return rows, blockers, warnings


def _snapshot_create_current_sha(path: Path) -> str | None:
    try:
        import hashlib as _hashlib
        h = _hashlib.sha256()
        with Path(path).open("rb") as f:
            for chunk in iter(lambda: f.read(1024 * 1024), b""):
                h.update(chunk)
        return h.hexdigest()
    except Exception:
        return None


def _snapshot_create_is_expected_volatile(path: str) -> bool:
    return _snapshot_readiness_is_expected_volatile(path)


def _snapshot_create_write_markdown(receipt: dict, md_path: Path) -> None:
    counts = receipt.get("counts", {})
    lines = [
        "# Patch 83 Snapshot Create Receipt",
        "",
        "Mode: SNAPSHOT CREATE ONLY. No restore authority exists.",
        f"Created: `{receipt.get('created_at')}`",
        f"Status: `{receipt.get('status')}`",
        f"Archive root: `{receipt.get('archive_root')}`",
        "",
        "## Counts",
        f"- Files copied: `{counts.get('files_copied')}`",
        f"- Warnings: `{counts.get('warnings')}`",
        f"- Blockers: `{counts.get('blockers')}`",
        "",
        "## Authority",
    ]
    for k, v in receipt.get("authority", {}).items():
        lines.append(f"- {k}: `{v}`")
    lines.extend(["", "## Warnings"])
    for item in receipt.get("warnings", []) or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "## Copied Files"])
    for row in receipt.get("copied_files", [])[:200]:
        lines.append(f"- `{row.get('snapshot_relative_path')}` ← `{row.get('source_path')}` sha16=`{row.get('sha256_16')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_create_build_archive() -> tuple[dict, Path | None, Path | None]:
    import shutil as _shutil
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    manifest_path = _snapshot_manifest_latest_path()
    readiness_path = _snapshot_readiness_latest_path()
    manifest = _snapshot_manifest_load(manifest_path) if manifest_path else None
    readiness = _snapshot_readiness_load(readiness_path) if readiness_path else None
    receipt = {
        "schema_version": SNAPSHOT_CREATE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_CREATE_V1_PATCH83",
        "created_at": now,
        "mode": "SNAPSHOT_CREATE_ONLY_NO_RESTORE_NO_PROJECT_WRITE",
        "status": "REFUSED",
        "authority": _snapshot_create_authority(),
        "sources": {
            "snapshot_manifest": str(manifest_path) if manifest_path else None,
            "snapshot_readiness": str(readiness_path) if readiness_path else None,
        },
        "archive_root": None,
        "archive_files_dir": None,
        "copied_files": [],
        "blockers": [],
        "warnings": [],
        "counts": {"files_copied": 0, "blockers": 0, "warnings": 0},
        "plain_english": {
            "meaning": "This command creates a Forge-owned copy archive only. It does not restore, modify, delete, or authorize project files.",
            "next_safe_step": "Verify this snapshot with snapshot-create-verify. Restore remains unavailable until a separate future patch.",
        },
    }
    if not manifest_path or not manifest:
        receipt["blockers"].append("No valid latest snapshot manifest found. Run snapshot-manifest-dry-run first.")
    if not readiness_path or not readiness:
        receipt["blockers"].append("No valid latest snapshot readiness receipt found. Run snapshot-readiness-check first.")
    if receipt["blockers"]:
        receipt["counts"]["blockers"] = len(receipt["blockers"])
        json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.json"
        md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.md"
        json_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
        _snapshot_create_write_markdown(receipt, md_path)
        return receipt, json_path, md_path

    rows, blockers, warnings = _snapshot_create_preflight(manifest, readiness)
    receipt["warnings"].extend(warnings)
    current_rows: list[tuple[dict, str]] = []
    for row in rows:
        source = Path(str(row.get("path") or ""))
        ok, reason = _snapshot_manifest_safe_to_hash(source)
        if not ok:
            blockers.append(f"Unsafe or unreadable source refused: {source} ({reason})")
            continue
        expected_sha = str(row.get("sha256") or "")
        current_sha = _snapshot_create_current_sha(source)
        if not current_sha:
            blockers.append(f"Could not hash source before copy: {source}")
            continue
        if expected_sha and current_sha != expected_sha:
            if _snapshot_create_is_expected_volatile(str(source)):
                receipt["warnings"].append(f"Expected volatile source drift accepted for copy: {source}")
            else:
                blockers.append(f"Unexpected source drift before snapshot-create: {source}")
                continue
        current_rows.append((row, current_sha))

    if blockers:
        receipt["blockers"] = blockers
        receipt["counts"]["blockers"] = len(blockers)
        receipt["counts"]["warnings"] = len(receipt["warnings"])
        json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.json"
        md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.md"
        json_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
        _snapshot_create_write_markdown(receipt, md_path)
        return receipt, json_path, md_path

    archive_root = SNAPSHOT_ARCHIVES_DIR / f"{ts}_snapshot_archive"
    files_dir = archive_root / "files"
    files_dir.mkdir(parents=True, exist_ok=False)
    copied = []
    for idx, (row, current_sha) in enumerate(current_rows, start=1):
        source = Path(str(row.get("path")))
        safe_name = _snapshot_create_safe_name(row, idx)
        dest = files_dir / safe_name
        _shutil.copy2(source, dest)
        copied_sha = _snapshot_create_current_sha(dest)
        if copied_sha != current_sha:
            receipt["warnings"].append(f"Copied hash mismatch after copy: {source}")
        copied.append({
            "source_path": str(source),
            "snapshot_relative_path": str(dest.relative_to(archive_root)),
            "source_label": row.get("label") or row.get("relative_path"),
            "source_root_label": row.get("root_label"),
            "sha256": copied_sha,
            "sha256_16": copied_sha[:16] if copied_sha else None,
            "size_bytes": dest.stat().st_size if dest.exists() else None,
            "expected_manifest_sha256": row.get("sha256"),
            "expected_volatile": _snapshot_create_is_expected_volatile(str(source)),
        })
    receipt.update({
        "status": "SNAPSHOT_CREATED_NO_RESTORE_AUTHORITY",
        "archive_root": str(archive_root),
        "archive_files_dir": str(files_dir),
        "copied_files": copied,
    })
    receipt["counts"] = {
        "files_copied": len(copied),
        "blockers": 0,
        "warnings": len(receipt["warnings"]),
    }
    json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.json"
    md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_PREFIX}.md"
    receipt["receipt_json"] = str(json_path)
    receipt["receipt_markdown"] = str(md_path)
    json_path.write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_create_write_markdown(receipt, md_path)
    (archive_root / "SNAPSHOT_CREATE_RECEIPT.json").write_text(json.dumps(receipt, indent=2, ensure_ascii=False), encoding="utf-8")
    (archive_root / "SOURCE_MANIFEST.json").write_text(json.dumps(manifest, indent=2, ensure_ascii=False), encoding="utf-8")
    (archive_root / "SOURCE_READINESS.json").write_text(json.dumps(readiness, indent=2, ensure_ascii=False), encoding="utf-8")
    return receipt, json_path, md_path


def _snapshot_create_print_summary(receipt: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    counts = receipt.get("counts", {}) or {}
    print()
    print("── Snapshot Create, No Restore ──────────────────────")
    print("  Mode      : CREATE ARCHIVE ONLY — no restore authority")
    print(f"  Status    : {receipt.get('status')}")
    print(f"  Files     : {counts.get('files_copied')}")
    print(f"  Blockers  : {counts.get('blockers')}")
    print(f"  Warnings  : {counts.get('warnings')}")
    if receipt.get("archive_root"):
        print(f"  Archive   : {receipt.get('archive_root')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO restore, NO project writes, NO delete/quarantine")
    if receipt.get("blockers"):
        print("  Blockers:")
        for item in receipt.get("blockers", [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def _snapshot_create_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_create_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_ARCHIVES_DIR / target
    return p


def _snapshot_create_verify_receipt(receipt: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(receipt, dict):
        return False, ["snapshot create receipt is not a JSON object"], warnings
    if receipt.get("schema_version") != SNAPSHOT_CREATE_SCHEMA_VERSION:
        problems.append("schema_version mismatch")
    if receipt.get("status") != "SNAPSHOT_CREATED_NO_RESTORE_AUTHORITY":
        problems.append(f"receipt status is not created: {receipt.get('status')}")
    authority = receipt.get("authority", {}) or {}
    for key in ["restore_authority", "shadow_restore_authority", "project_file_write_authority", "engine_file_write_authority", "delete_authority", "quarantine_authority", "shell_access", "chroma_write_authority", "final_lockfile_authority"]:
        if authority.get(key) is not False:
            problems.append(f"forbidden authority flag not false: {key}")
    archive_root = Path(str(receipt.get("archive_root") or ""))
    if not archive_root.exists() or not archive_root.is_dir():
        problems.append("archive_root missing or not a directory")
    for row in receipt.get("copied_files", []) or []:
        rel = str(row.get("snapshot_relative_path") or "")
        if not rel or rel.startswith("/") or ".." in Path(rel).parts:
            problems.append(f"unsafe snapshot relative path in receipt: {rel}")
            continue
        dest = archive_root / rel
        if not dest.exists() or not dest.is_file():
            problems.append(f"copied file missing: {rel}")
            continue
        sha = _snapshot_create_current_sha(dest)
        if sha != row.get("sha256"):
            problems.append(f"copied file hash mismatch: {rel}")
    if receipt.get("warnings"):
        warnings.extend(receipt.get("warnings") or [])
    return not problems, problems, warnings


def cmd_snapshot_archive_policy(session_id: str) -> None:
    """Show Patch 83 snapshot-create/no-restore policy. Usage: snapshot-archive-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_archive_policy_payload()
    print()
    print("── Snapshot Archive Policy ──────────────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned snapshot archive receipts/files only")
    print("  Authority : CREATE snapshot archive only; NO restore, NO project writes")
    print("  Required  : latest manifest + readiness receipt with zero blockers")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_ARCHIVE_POLICY_SHOWN", "-", "create-only-no-restore", "patch83")


def cmd_snapshot_create(session_id: str) -> None:
    """Create a Forge-owned snapshot archive. Usage: snapshot-create"""
    from agents.forge.memory import write_audit_entry
    receipt, json_path, md_path = _snapshot_create_build_archive()
    _snapshot_create_print_summary(receipt, json_path, md_path)
