def cmd_snapshot_create_show(arg: str, session_id: str) -> None:
    """Show a snapshot create receipt. Usage: snapshot-create-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_create_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No snapshot create receipt found. Run: snapshot-create")
        print()
        return
    receipt = _snapshot_create_load(path)
    if not receipt:
        print()
        print(f"  Could not read snapshot create receipt JSON: {path}")
        print()
        return
    _snapshot_create_print_summary(receipt, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_CREATE_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_create_verify(arg: str, session_id: str) -> None:
    """Verify a snapshot create receipt and copied files. Usage: snapshot-create-verify [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_create_resolve_path(arg)
    print()
    print("── Snapshot Create Verify ───────────────────────────")
    if not path or not path.exists():
        print("  Status    : FAIL")
        print("  Reason    : no snapshot create receipt found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    receipt = _snapshot_create_load(path)
    ok, problems, warnings = _snapshot_create_verify_receipt(receipt or {})
    print(f"  Receipt   : {path}")
    print(f"  Status    : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    if problems:
        for item in problems[:50]:
            print(f"    - {item}")
    if warnings:
        print("  Warning notes:")
        for item in warnings[:20]:
            print(f"    - {item}")
    print("  Authority : NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_CREATE_VERIFY_" + ("PASS" if ok else "FAIL"), str(path), f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_create_export(session_id: str) -> None:
    """Export snapshot create receipt index. Usage: snapshot-create-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    rows = []
    for p in _snapshot_create_paths():
        r = _snapshot_create_load(p) or {}
        rows.append({
            "path": str(p),
            "created_at": r.get("created_at"),
            "status": r.get("status"),
            "archive_root": r.get("archive_root"),
            "files_copied": (r.get("counts") or {}).get("files_copied"),
            "warnings": (r.get("counts") or {}).get("warnings"),
            "blockers": (r.get("counts") or {}).get("blockers"),
        })
    payload = {
        "schema_version": SNAPSHOT_CREATE_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_CREATE_EXPORT_V1_PATCH83",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_create_authority(),
        "count": len(rows),
        "snapshot_create_receipts": rows,
    }
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_CREATE_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 83 Snapshot Create Export",
        "",
        "Mode: EXPORT ONLY. No restore authority exists.",
        f"Generated: `{payload.get('created_at')}`",
        f"Snapshot create receipts: **{len(rows)}**",
        "",
    ]
    for row in rows[:100]:
        lines.append(f"- `{row.get('created_at')}` status=`{row.get('status')}` files=`{row.get('files_copied')}` archive=`{row.get('archive_root')}` receipt=`{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Snapshot Create Export ───────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  JSON      :", json_path)
    print("  Markdown  :", md_path)
    print("  Receipts  :", len(rows))
    print("  Authority : NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_CREATE_EXPORT_WRITTEN", str(json_path), str(md_path), f"receipts={len(rows)}")


# ─── PATCH 84 — SNAPSHOT DIFF / VERIFY INDEX (NO RESTORE AUTHORITY) ────────

SNAPSHOT_DIFF_SCHEMA_VERSION = "snapshot_diff_verify_index_v1_patch84"
SNAPSHOT_DIFF_POLICY_VERSION = "patch84_snapshot_diff_verify_index_v1"
SNAPSHOT_VERIFY_INDEX_PREFIX = "snapshot_verify_index_v1"
SNAPSHOT_DIFF_REPORT_PREFIX = "snapshot_diff_report_v1"
SNAPSHOT_DIFF_EXPORT_PREFIX = "snapshot_diff_export_v1"


def _snapshot_diff_authority() -> dict:
    return {
        "restore_authority": False,
        "shadow_restore_authority": False,
        "project_write_authority": False,
        "engine_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "final_lockfile_authority": False,
        "snapshot_create_authority": False,
    }


def _snapshot_diff_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_DIFF_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_DIFF_POLICY_VERSION,
        "policy": "Patch 84 Snapshot Diff / Verify Index",
        "mode": "READ_ONLY_SNAPSHOT_INDEX_AND_DIFF_NO_RESTORE",
        "purpose": "Verify existing snapshot create receipts and compare snapshot receipt metadata without adding restore, deletion, quarantine, or project-write authority.",
        "writes": [
            "Forge-owned snapshot verification index receipts under memory/snapshots_v1/",
            "Forge-owned snapshot diff reports under memory/snapshots_v1/",
            "Forge-owned export receipts under memory/snapshots_v1/",
        ],
        "forbidden": [
            "No restore command",
            "No shadow restore command",
            "No project file writes",
            "No engine file writes",
            "No deletion",
            "No quarantine",
            "No shell execution",
            "No Chroma writes",
            "No final lockfile authority",
            "No new snapshot archive creation from this patch",
        ],
        "authority": _snapshot_diff_authority(),
        "safe_next_step": "After this passes, a later patch may add shadow-restore planning only. Actual restore remains unavailable.",
    }


def _snapshot_verify_index_paths() -> list[Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_ARCHIVES_DIR.glob(f"*_{SNAPSHOT_VERIFY_INDEX_PREFIX}.json"), reverse=True)


def _snapshot_diff_report_paths() -> list[Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_ARCHIVES_DIR.glob(f"*_{SNAPSHOT_DIFF_REPORT_PREFIX}.json"), reverse=True)


def _snapshot_diff_export_paths() -> list[Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_ARCHIVES_DIR.glob(f"*_{SNAPSHOT_DIFF_EXPORT_PREFIX}.json"), reverse=True)


def _snapshot_diff_latest_report_path() -> Path | None:
    reports = _snapshot_diff_report_paths() + _snapshot_verify_index_paths()
    reports = sorted(reports, reverse=True)
    return reports[0] if reports else None


def _snapshot_diff_load(path: Path) -> dict | None:
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_create_receipt_rows() -> list[dict]:
    rows = []
    for path in _snapshot_create_paths():
        receipt = _snapshot_create_load(path) or {}
        ok, problems, warnings = _snapshot_create_verify_receipt(receipt)
        rows.append({
            "receipt_path": str(path),
            "created_at": receipt.get("created_at"),
            "status": receipt.get("status"),
            "archive_root": receipt.get("archive_root"),
            "archive_files_dir": receipt.get("archive_files_dir"),
            "files_copied": len(receipt.get("copied_files") or []),
            "blocker_count": len(receipt.get("blockers") or []),
            "warning_count": len(receipt.get("warnings") or []),
            "verify_status": "PASS" if ok else "FAIL",
            "verify_problem_count": len(problems),
            "verify_warning_count": len(warnings),
            "verify_problems": problems[:50],
            "verify_warnings": warnings[:50],
        })
    return rows


def _snapshot_verify_index_build() -> dict:
    rows = _snapshot_create_receipt_rows()
    failures = [r for r in rows if r.get("verify_status") != "PASS"]
    status = "PASS" if rows and not failures else ("NO_SNAPSHOTS_FOUND" if not rows else "FAIL")
    return {
        "schema_version": SNAPSHOT_DIFF_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_VERIFY_INDEX_V1_PATCH84",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "READ_ONLY_VERIFY_INDEX_NO_RESTORE",
        "status": status,
        "authority": _snapshot_diff_authority(),
        "counts": {
            "snapshot_receipts": len(rows),
            "passing_receipts": len([r for r in rows if r.get("verify_status") == "PASS"]),
            "failing_receipts": len(failures),
        },
        "snapshot_receipts": rows,
        "plain_english": {
            "meaning": "Forge verified existing snapshot-create receipts and copied snapshot files where possible.",
            "next_safe_step": "Use snapshot-diff to compare snapshot metadata. Restore remains unavailable.",
        },
    }


def _snapshot_verify_index_write(report: dict) -> tuple[Path, Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_VERIFY_INDEX_PREFIX}.json"
    md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_VERIFY_INDEX_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 84 Snapshot Verify Index",
        "",
        "Mode: READ-ONLY VERIFY INDEX. No restore authority exists.",
        f"Generated: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        f"Snapshot receipts: **{(report.get('counts') or {}).get('snapshot_receipts')}**",
        f"Passing receipts: **{(report.get('counts') or {}).get('passing_receipts')}**",
        f"Failing receipts: **{(report.get('counts') or {}).get('failing_receipts')}**",
        "",
        "## Receipts",
    ]
    for row in report.get("snapshot_receipts", [])[:100]:
        lines.append(f"- `{row.get('created_at')}` status=`{row.get('status')}` verify=`{row.get('verify_status')}` files=`{row.get('files_copied')}` receipt=`{row.get('receipt_path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return json_path, md_path


def _snapshot_diff_file_map(receipt: dict) -> dict:
    out = {}
    for row in receipt.get("copied_files") or []:
        key = row.get("source_path") or row.get("snapshot_relative_path") or row.get("source_label")
        if not key:
            continue
        out[str(key)] = {
            "source_path": row.get("source_path"),
            "source_label": row.get("source_label"),
            "snapshot_relative_path": row.get("snapshot_relative_path"),
            "sha256": row.get("sha256"),
            "size_bytes": row.get("size_bytes"),
            "expected_volatile": bool(row.get("expected_volatile")),
        }
    return out


def _snapshot_diff_build(arg: str = "latest") -> dict:
    receipts = _snapshot_create_paths()
    if len(receipts) < 2:
        latest = _snapshot_create_load(receipts[0]) if receipts else None
        return {
            "schema_version": SNAPSHOT_DIFF_SCHEMA_VERSION,
            "report_type": "SNAPSHOT_DIFF_REPORT_V1_PATCH84",
            "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
            "mode": "READ_ONLY_DIFF_NO_RESTORE",
            "status": "NOT_ENOUGH_SNAPSHOTS_TO_DIFF",
            "authority": _snapshot_diff_authority(),
            "requested_arg": arg or "latest",
            "snapshot_count": len(receipts),
            "latest_snapshot": {
                "path": str(receipts[0]) if receipts else None,
                "created_at": latest.get("created_at") if latest else None,
                "status": latest.get("status") if latest else None,
                "files_copied": len((latest or {}).get("copied_files") or []),
            },
            "summary": {
                "added": 0,
                "removed": 0,
                "changed": 0,
                "unchanged": len((latest or {}).get("copied_files") or []),
                "volatile_changed": 0,
            },
            "added_files": [],
            "removed_files": [],
            "changed_files": [],
            "plain_english": {
                "meaning": "Only one snapshot exists, so Forge cannot compare two snapshot receipts yet. This is normal after the first snapshot-create patch.",
                "next_safe_step": "Create another snapshot in a later controlled flow, then run snapshot-diff again. Restore remains unavailable.",
            },
        }
    newest_path, previous_path = receipts[0], receipts[1]
    newest = _snapshot_create_load(newest_path) or {}
    previous = _snapshot_create_load(previous_path) or {}
    new_map = _snapshot_diff_file_map(newest)
    old_map = _snapshot_diff_file_map(previous)
    new_keys = set(new_map)
    old_keys = set(old_map)
    added = sorted(new_keys - old_keys)
    removed = sorted(old_keys - new_keys)
    common = sorted(new_keys & old_keys)
    changed = []
    unchanged = 0
    volatile_changed = 0
    for key in common:
        n = new_map[key]
        o = old_map[key]
        if n.get("sha256") != o.get("sha256") or n.get("size_bytes") != o.get("size_bytes"):
            item = {
                "source_path": key,
                "old_sha256": o.get("sha256"),
                "new_sha256": n.get("sha256"),
                "old_size_bytes": o.get("size_bytes"),
                "new_size_bytes": n.get("size_bytes"),
                "expected_volatile": bool(n.get("expected_volatile") or o.get("expected_volatile")),
            }
            if item["expected_volatile"]:
                volatile_changed += 1
            changed.append(item)
        else:
            unchanged += 1
    status = "DIFF_READY"
    return {
        "schema_version": SNAPSHOT_DIFF_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_DIFF_REPORT_V1_PATCH84",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "READ_ONLY_DIFF_NO_RESTORE",
        "status": status,
        "authority": _snapshot_diff_authority(),
        "requested_arg": arg or "latest",
        "new_snapshot": {"path": str(newest_path), "created_at": newest.get("created_at"), "status": newest.get("status"), "files_copied": len(newest.get("copied_files") or [])},
        "previous_snapshot": {"path": str(previous_path), "created_at": previous.get("created_at"), "status": previous.get("status"), "files_copied": len(previous.get("copied_files") or [])},
        "summary": {"added": len(added), "removed": len(removed), "changed": len(changed), "unchanged": unchanged, "volatile_changed": volatile_changed},
        "added_files": added[:500],
        "removed_files": removed[:500],
        "changed_files": changed[:500],
        "plain_english": {
            "meaning": "Forge compared snapshot receipt metadata and copied-file hashes. This is only a report; it does not restore or modify files.",
            "next_safe_step": "Review differences. A future patch may add shadow-restore planning only after diff/index behavior is trusted.",
        },
    }


def _snapshot_diff_write(report: dict) -> tuple[Path, Path]:
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_DIFF_REPORT_PREFIX}.json"
    md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_DIFF_REPORT_PREFIX}.md"
    json_path.write_text(json.dumps(report, indent=2, ensure_ascii=False), encoding="utf-8")
    s = report.get("summary") or {}
    lines = [
        "# Patch 84 Snapshot Diff Report",
        "",
        "Mode: READ-ONLY DIFF. No restore authority exists.",
        f"Generated: `{report.get('created_at')}`",
        f"Status: `{report.get('status')}`",
        "",
        "## Summary",
        f"- Added: **{s.get('added', 0)}**",
        f"- Removed: **{s.get('removed', 0)}**",
        f"- Changed: **{s.get('changed', 0)}**",
        f"- Unchanged: **{s.get('unchanged', 0)}**",
        f"- Expected volatile changed: **{s.get('volatile_changed', 0)}**",
        "",
        "## Authority",
        "No restore. No shadow restore. No project writes.",
    ]
    if report.get("status") == "NOT_ENOUGH_SNAPSHOTS_TO_DIFF":
        lines.extend(["", "## Note", report.get("plain_english", {}).get("meaning", "Only one snapshot exists.")])
    else:
        lines.extend(["", "## Changed files (first 50)"])
        for row in report.get("changed_files", [])[:50]:
            lines.append(f"- `{row.get('source_path')}` volatile=`{row.get('expected_volatile')}` old=`{str(row.get('old_sha256'))[:16]}` new=`{str(row.get('new_sha256'))[:16]}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    return json_path, md_path


def _snapshot_diff_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target == "latest":
        return _snapshot_diff_latest_report_path()
    p = Path(target)
    if p.is_absolute():
        return p
    candidate = SNAPSHOT_ARCHIVES_DIR / target
    return candidate if candidate.exists() else None


def _snapshot_diff_print_report(report: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    s = report.get("summary") or {}
    print()
    print("── Snapshot Diff / Verify Report ────────────────────")
    print(f"  Type      : {report.get('report_type')}")
    print(f"  Status    : {report.get('status')}")
    print(f"  Created   : {report.get('created_at')}")
    if report.get("report_type") == "SNAPSHOT_VERIFY_INDEX_V1_PATCH84":
        c = report.get("counts") or {}
        print(f"  Receipts  : {c.get('snapshot_receipts')}")
        print(f"  Passing   : {c.get('passing_receipts')}")
        print(f"  Failing   : {c.get('failing_receipts')}")
    else:
        print(f"  Added     : {s.get('added', 0)}")
        print(f"  Removed   : {s.get('removed', 0)}")
        print(f"  Changed   : {s.get('changed', 0)}")
        print(f"  Unchanged : {s.get('unchanged', 0)}")
        print(f"  Volatile  : {s.get('volatile_changed', 0)}")
        note = (report.get("plain_english") or {}).get("meaning")
        if note:
            print(f"  Meaning   : {note}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()


def cmd_snapshot_diff_policy(session_id: str) -> None:
    """Show Patch 84 snapshot diff/index policy. Usage: snapshot-diff-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_diff_policy_payload()
    print()
    print("── Snapshot Diff / Verify Policy ────────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned diff/index receipts only")
    print("  Authority : NO restore, NO shadow restore, NO project writes")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_DIFF_POLICY_SHOWN", "-", "read-only", "patch84")


def cmd_snapshot_verify_index(session_id: str) -> None:
    """Verify all snapshot create receipts. Usage: snapshot-verify-index"""
    from agents.forge.memory import write_audit_entry
    report = _snapshot_verify_index_build()
    json_path, md_path = _snapshot_verify_index_write(report)
    _snapshot_diff_print_report(report, json_path, md_path)
    write_audit_entry(session_id, "SNAPSHOT_VERIFY_INDEX_WRITTEN", str(json_path), f"status={report.get('status')}", f"receipts={(report.get('counts') or {}).get('snapshot_receipts')}")


def cmd_snapshot_diff(arg: str, session_id: str) -> None:
    """Compare snapshot create receipts. Usage: snapshot-diff [latest]"""
    from agents.forge.memory import write_audit_entry
    report = _snapshot_diff_build(arg or "latest")
    json_path, md_path = _snapshot_diff_write(report)
    _snapshot_diff_print_report(report, json_path, md_path)
    write_audit_entry(session_id, "SNAPSHOT_DIFF_WRITTEN", str(json_path), f"status={report.get('status')}", f"changed={(report.get('summary') or {}).get('changed', 0)}")


def cmd_snapshot_diff_show(arg: str, session_id: str) -> None:
    """Show latest snapshot diff/index report. Usage: snapshot-diff-show [latest|file]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_diff_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No snapshot diff/index report found. Run: snapshot-verify-index or snapshot-diff")
        print()
        return
    report = _snapshot_diff_load(path) or {}
    _snapshot_diff_print_report(report, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_DIFF_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_diff_export(session_id: str) -> None:
    """Export snapshot diff/index report list. Usage: snapshot-diff-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_ARCHIVES_DIR.mkdir(parents=True, exist_ok=True)
    rows = []
    for path in _snapshot_verify_index_paths() + _snapshot_diff_report_paths():
        report = _snapshot_diff_load(path) or {}
        rows.append({
            "path": str(path),
            "report_type": report.get("report_type"),
            "created_at": report.get("created_at"),
            "status": report.get("status"),
            "counts": report.get("counts") or report.get("summary") or {},
        })
    rows = sorted(rows, key=lambda r: (r.get("created_at") or "", r.get("path") or ""), reverse=True)
    payload = {
        "schema_version": SNAPSHOT_DIFF_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_DIFF_EXPORT_V1_PATCH84",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_RESTORE_NO_PROJECT_WRITE",
        "authority": _snapshot_diff_authority(),
        "count": len(rows),
        "reports": rows,
    }
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_DIFF_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_ARCHIVES_DIR / f"{ts}_{SNAPSHOT_DIFF_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 84 Snapshot Diff Export",
        "",
        "Mode: EXPORT ONLY. No restore authority exists.",
        f"Generated: `{payload.get('created_at')}`",
        f"Reports: **{len(rows)}**",
        "",
    ]
    for row in rows[:100]:
        lines.append(f"- `{row.get('created_at')}` type=`{row.get('report_type')}` status=`{row.get('status')}` path=`{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Snapshot Diff Export ─────────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  JSON      :", json_path)
    print("  Markdown  :", md_path)
    print("  Reports   :", len(rows))
    print("  Authority : NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_DIFF_EXPORT_WRITTEN", str(json_path), str(md_path), f"reports={len(rows)}")


# ─── PATCH 85 — SHADOW RESTORE PLAN (PLAN ONLY, NO COPY/RESTORE) ───────────

SNAPSHOT_SHADOW_PLAN_SCHEMA_VERSION = "snapshot_shadow_restore_plan_v1_patch85"
SNAPSHOT_SHADOW_PLAN_POLICY_VERSION = "patch85_shadow_restore_plan_v1"
SNAPSHOT_SHADOW_PLANS_DIR = MEMORY_DIR / "shadow_restore_plans_v1"
SNAPSHOT_SHADOW_PLAN_PREFIX = "snapshot_shadow_restore_plan_v1"
SNAPSHOT_SHADOW_EXPORT_PREFIX = "snapshot_shadow_restore_export_v1"


def _snapshot_shadow_authority() -> dict:
    return {
        "shadow_restore_plan_authority": True,
        "shadow_restore_copy_authority": False,
        "restore_authority": False,
        "project_file_write_authority": False,
        "engine_file_write_authority": False,
        "delete_authority": False,
        "quarantine_authority": False,
        "shell_execution_authority": False,
        "chroma_write_authority": False,
        "snapshot_create_authority": False,
        "final_lockfile_authority": False,
    }


def _snapshot_shadow_policy_payload() -> dict:
    return {
        "schema_version": SNAPSHOT_SHADOW_PLAN_SCHEMA_VERSION,
        "policy_version": SNAPSHOT_SHADOW_PLAN_POLICY_VERSION,
        "policy": "Patch 85 Shadow Restore Plan",
        "mode": "PLAN_ONLY_NO_COPY_NO_RESTORE_NO_PROJECT_WRITE",
        "purpose": "Generate a read-only plan showing what a future shadow restore would copy into a Forge-owned shadow area. This patch does not copy files and cannot restore anything.",
        "authority": _snapshot_shadow_authority(),
        "allowed_writes": [
            "Forge-owned shadow restore plan JSON/Markdown receipts under /home/nic/forge/memory/shadow_restore_plans_v1/",
            "Forge audit entries for policy/plan/show/validate/export commands",
        ],
        "forbidden": [
            "copying files into a shadow restore folder",
            "restoring files to /home/nic/forge or /home/nic/aiweb",
            "editing, deleting, moving, quarantining, or promoting engines",
            "granting final lockfile authority",
            "running shell commands",
            "writing to Chroma or old vector DBs",
            "reading or copying secrets, credentials, keys, .env, ~/.ssh, or token files",
        ],
        "required_inputs": [
            "latest snapshot create receipt",
            "snapshot-create-verify must pass for the source receipt",
        ],
    }


def _snapshot_shadow_paths() -> list[Path]:
    SNAPSHOT_SHADOW_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    return sorted(SNAPSHOT_SHADOW_PLANS_DIR.glob(f"*_{SNAPSHOT_SHADOW_PLAN_PREFIX}.json"), reverse=True)


def _snapshot_shadow_latest_path() -> Path | None:
    paths = _snapshot_shadow_paths()
    return paths[0] if paths else None


def _snapshot_shadow_resolve_path(arg: str) -> Path | None:
    target = (arg or "latest").strip()
    if target.lower() in {"latest", ""}:
        return _snapshot_shadow_latest_path()
    p = Path(os.path.expanduser(target))
    if not p.is_absolute():
        p = SNAPSHOT_SHADOW_PLANS_DIR / target
    return p


def _snapshot_shadow_load(path: Path) -> dict | None:
    try:
        return json.loads(Path(path).read_text(encoding="utf-8"))
    except Exception:
        return None


def _snapshot_shadow_safe_rel(row: dict, idx: int) -> str:
    source_path = Path(str(row.get("source_path") or "unknown"))
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", source_path.name or "file").strip("._-") or "file"
    sha16 = str(row.get("sha256_16") or row.get("sha256") or "nohash")[:16]
    return f"shadow_files/{idx:04d}_{sha16}_{name}"


def _snapshot_shadow_build_plan(arg: str = "latest") -> tuple[dict, Path, Path]:
    now = datetime.datetime.now().isoformat(timespec="seconds")
    ts = _patch60_timestamp()
    SNAPSHOT_SHADOW_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    receipt_path = _snapshot_create_resolve_path(arg or "latest")
    receipt = _snapshot_create_load(receipt_path) if receipt_path and receipt_path.exists() else None
    blockers: list[str] = []
    warnings: list[str] = []
    if not receipt_path or not receipt_path.exists():
        blockers.append("No snapshot create receipt found. Run snapshot-create first.")
    if not receipt:
        blockers.append("Snapshot create receipt could not be loaded as JSON.")
    verify_ok = False
    verify_problems: list[str] = []
    verify_warnings: list[str] = []
    if receipt:
        verify_ok, verify_problems, verify_warnings = _snapshot_create_verify_receipt(receipt)
        if not verify_ok:
            blockers.append(f"Source snapshot create receipt failed verification: {len(verify_problems)} problems")
        warnings.extend(verify_warnings)
    archive_root = str((receipt or {}).get("archive_root") or "")
    planned_files: list[dict] = []
    for idx, row in enumerate((receipt or {}).get("copied_files") or [], start=1):
        rel = str(row.get("snapshot_relative_path") or "")
        if not rel or rel.startswith("/") or ".." in Path(rel).parts:
            blockers.append(f"Unsafe snapshot relative path in source receipt: {rel}")
            continue
        planned_files.append({
            "source_path": row.get("source_path"),
            "snapshot_archive_file": str(Path(archive_root) / rel) if archive_root else rel,
            "snapshot_relative_path": rel,
            "planned_shadow_relative_path": _snapshot_shadow_safe_rel(row, idx),
            "sha256": row.get("sha256"),
            "sha256_16": row.get("sha256_16") or str(row.get("sha256") or "")[:16],
            "size_bytes": row.get("size_bytes"),
            "expected_volatile": row.get("expected_volatile", False),
            "future_action": "WOULD_COPY_TO_FORGE_OWNED_SHADOW_AREA_ONLY_IN_FUTURE_PATCH",
        })
    if receipt and not planned_files:
        blockers.append("Snapshot receipt contains no planned files.")
    status = "SHADOW_RESTORE_PLAN_READY_NO_COPY_NO_RESTORE" if not blockers else "SHADOW_RESTORE_PLAN_BLOCKED_NO_COPY_NO_RESTORE"
    planned_shadow_root = str(SNAPSHOT_SHADOW_PLANS_DIR / f"{ts}_shadow_restore_target_NOT_CREATED")
    plan = {
        "schema_version": SNAPSHOT_SHADOW_PLAN_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_SHADOW_RESTORE_PLAN_V1_PATCH85",
        "created_at": now,
        "mode": "PLAN_ONLY_NO_COPY_NO_RESTORE_NO_PROJECT_WRITE",
        "status": status,
        "authority": _snapshot_shadow_authority(),
        "source_snapshot_receipt": str(receipt_path) if receipt_path else None,
        "source_snapshot_status": (receipt or {}).get("status") if receipt else None,
        "source_archive_root": archive_root or None,
        "planned_shadow_root_NOT_CREATED": planned_shadow_root,
        "planned_files": planned_files,
        "blockers": blockers,
        "warnings": warnings,
        "counts": {
            "planned_files": len(planned_files),
            "blockers": len(blockers),
            "warnings": len(warnings),
            "source_verify_problems": len(verify_problems),
            "source_verify_warnings": len(verify_warnings),
        },
        "plain_english": {
            "meaning": "This is only a map of what a future shadow restore would copy into a Forge-owned shadow folder. No files were copied and no restore authority exists.",
            "next_safe_step": "Review with snapshot-shadow-show and validate with snapshot-shadow-validate. Actual shadow-copy behavior must be a separate future patch.",
        },
    }
    json_path = SNAPSHOT_SHADOW_PLANS_DIR / f"{ts}_{SNAPSHOT_SHADOW_PLAN_PREFIX}.json"
    md_path = SNAPSHOT_SHADOW_PLANS_DIR / f"{ts}_{SNAPSHOT_SHADOW_PLAN_PREFIX}.md"
    json_path.write_text(json.dumps(plan, indent=2, ensure_ascii=False), encoding="utf-8")
    _snapshot_shadow_write_markdown(plan, md_path)
    return plan, json_path, md_path


def _snapshot_shadow_write_markdown(plan: dict, md_path: Path) -> None:
    lines = [
        "# Patch 85 Shadow Restore Plan",
        "",
        "Mode: PLAN ONLY. No files copied. No restore authority exists.",
        f"Created: `{plan.get('created_at')}`",
        f"Status: `{plan.get('status')}`",
        f"Source snapshot receipt: `{plan.get('source_snapshot_receipt')}`",
        f"Planned shadow root NOT CREATED: `{plan.get('planned_shadow_root_NOT_CREATED')}`",
        "",
        "## Counts",
        f"- Planned files: `{(plan.get('counts') or {}).get('planned_files')}`",
        f"- Blockers: `{(plan.get('counts') or {}).get('blockers')}`",
        f"- Warnings: `{(plan.get('counts') or {}).get('warnings')}`",
        "",
        "## Authority",
    ]
    for k, v in (plan.get("authority") or {}).items():
        lines.append(f"- {k}: `{v}`")
    lines.extend(["", "## Blockers"])
    for item in plan.get("blockers") or ["None"]:
        lines.append(f"- {item}")
    lines.extend(["", "## Planned Files"])
    for row in (plan.get("planned_files") or [])[:200]:
        lines.append(f"- `{row.get('planned_shadow_relative_path')}` ← `{row.get('snapshot_relative_path')}` → original `{row.get('source_path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")


def _snapshot_shadow_print(plan: dict, json_path: Path | None = None, md_path: Path | None = None) -> None:
    c = plan.get("counts") or {}
    print()
    print("── Snapshot Shadow Restore Plan ─────────────────────")
    print("  Mode      : PLAN ONLY — no copy, no restore")
    print(f"  Status    : {plan.get('status')}")
    print(f"  Files     : {c.get('planned_files')}")
    print(f"  Blockers  : {c.get('blockers')}")
    print(f"  Warnings  : {c.get('warnings')}")
    print(f"  Source    : {plan.get('source_snapshot_receipt')}")
    if json_path:
        print(f"  JSON      : {json_path}")
    if md_path:
        print(f"  Markdown  : {md_path}")
    print("  Authority : NO copy, NO restore, NO project writes")
    if plan.get("blockers"):
        print("  Blockers:")
        for item in (plan.get("blockers") or [])[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()


def _snapshot_shadow_validate_plan(plan: dict) -> tuple[bool, list[str], list[str]]:
    problems: list[str] = []
    warnings: list[str] = []
    if not isinstance(plan, dict):
        return False, ["shadow restore plan is not a JSON object"], warnings
    if plan.get("schema_version") != SNAPSHOT_SHADOW_PLAN_SCHEMA_VERSION:
        problems.append("schema_version mismatch")
    if plan.get("mode") != "PLAN_ONLY_NO_COPY_NO_RESTORE_NO_PROJECT_WRITE":
        problems.append("mode is not plan-only")
    authority = plan.get("authority") or {}
    for key in ["shadow_restore_copy_authority", "restore_authority", "project_file_write_authority", "engine_file_write_authority", "delete_authority", "quarantine_authority", "shell_execution_authority", "chroma_write_authority", "snapshot_create_authority", "final_lockfile_authority"]:
        if authority.get(key) is not False:
            problems.append(f"forbidden authority flag not false: {key}")
    planned_root = str(plan.get("planned_shadow_root_NOT_CREATED") or "")
    if planned_root and Path(planned_root).exists():
        problems.append("planned shadow root unexpectedly exists; Patch 85 must not create it")
    for row in plan.get("planned_files") or []:
        rel = str(row.get("planned_shadow_relative_path") or "")
        if not rel or rel.startswith("/") or ".." in Path(rel).parts:
            problems.append(f"unsafe planned shadow relative path: {rel}")
        src_rel = str(row.get("snapshot_relative_path") or "")
        if src_rel.startswith("/") or ".." in Path(src_rel).parts:
            problems.append(f"unsafe source snapshot relative path: {src_rel}")
    if plan.get("warnings"):
        warnings.extend(plan.get("warnings") or [])
    return not problems and not plan.get("blockers"), problems + list(plan.get("blockers") or []), warnings


def cmd_snapshot_shadow_policy(session_id: str) -> None:
    """Show Patch 85 shadow restore plan policy. Usage: snapshot-shadow-policy"""
    from agents.forge.memory import write_audit_entry
    p = _snapshot_shadow_policy_payload()
    print()
    print("── Snapshot Shadow Restore Policy ───────────────────")
    print(f"  Policy    : {p.get('policy')}")
    print(f"  Mode      : {p.get('mode')}")
    print("  Writes    : Forge-owned shadow restore plan receipts only")
    print("  Authority : NO copy, NO restore, NO project writes")
    print("  Future    : shadow-copy must be a separate future patch")
    print()
    print("  Forbidden:")
    for item in p.get("forbidden", []):
        print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_SHADOW_POLICY_SHOWN", "-", "plan-only", "patch85")


def cmd_snapshot_shadow_plan(arg: str, session_id: str) -> None:
    """Write a shadow restore plan. Usage: snapshot-shadow-plan [latest|snapshot_receipt]"""
    from agents.forge.memory import write_audit_entry
    plan, json_path, md_path = _snapshot_shadow_build_plan(arg or "latest")
    _snapshot_shadow_print(plan, json_path, md_path)
    tool = "SNAPSHOT_SHADOW_PLAN_WRITTEN" if not plan.get("blockers") else "SNAPSHOT_SHADOW_PLAN_BLOCKED"
    write_audit_entry(session_id, tool, str(json_path), f"status={plan.get('status')} files={(plan.get('counts') or {}).get('planned_files')}", "no-copy-no-restore")


def cmd_snapshot_shadow_show(arg: str, session_id: str) -> None:
    """Show a shadow restore plan. Usage: snapshot-shadow-show [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_shadow_resolve_path(arg)
    if not path or not path.exists():
        print()
        print("  No shadow restore plan found. Run: snapshot-shadow-plan")
        print()
        return
    plan = _snapshot_shadow_load(path) or {}
    _snapshot_shadow_print(plan, Path(path), None)
    write_audit_entry(session_id, "SNAPSHOT_SHADOW_PLAN_SHOWN", str(path), "read-only", arg or "latest")


def cmd_snapshot_shadow_validate(arg: str, session_id: str) -> None:
    """Validate a shadow restore plan. Usage: snapshot-shadow-validate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_shadow_resolve_path(arg)
    print()
    print("── Snapshot Shadow Plan Validate ────────────────────")
    if not path or not path.exists():
        print("  Status    : FAIL")
        print("  Reason    : no shadow restore plan found")
        print("──────────────────────────────────────────────────────")
        print()
        return
    plan = _snapshot_shadow_load(path) or {}
    ok, problems, warnings = _snapshot_shadow_validate_plan(plan)
    print(f"  Status    : {'PASS' if ok else 'FAIL'}")
    print(f"  Problems  : {len(problems)}")
    print(f"  Warnings  : {len(warnings)}")
    print("  Authority : NO copy, NO restore, NO project writes")
    if problems:
        print("  Problems:")
        for item in problems[:20]:
            print(f"    - {item}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_SHADOW_VALIDATE_PASS" if ok else "SNAPSHOT_SHADOW_VALIDATE_FAIL", str(path), f"problems={len(problems)}", f"warnings={len(warnings)}")


def cmd_snapshot_shadow_export(session_id: str) -> None:
    """Export shadow restore plan index. Usage: snapshot-shadow-export"""
    from agents.forge.memory import write_audit_entry
    SNAPSHOT_SHADOW_PLANS_DIR.mkdir(parents=True, exist_ok=True)
    rows = []
    for path in _snapshot_shadow_paths():
        plan = _snapshot_shadow_load(path) or {}
        ok, problems, warnings = _snapshot_shadow_validate_plan(plan)
        rows.append({
            "path": str(path),
            "created_at": plan.get("created_at"),
            "status": plan.get("status"),
            "validate_status": "PASS" if ok else "FAIL",
            "planned_files": (plan.get("counts") or {}).get("planned_files"),
            "blockers": len(plan.get("blockers") or []),
            "warnings": len(warnings),
            "problems": len(problems),
        })
    payload = {
        "schema_version": SNAPSHOT_SHADOW_PLAN_SCHEMA_VERSION,
        "report_type": "SNAPSHOT_SHADOW_RESTORE_EXPORT_V1_PATCH85",
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "mode": "EXPORT_ONLY_NO_COPY_NO_RESTORE",
        "authority": _snapshot_shadow_authority(),
        "count": len(rows),
        "plans": rows,
    }
    ts = _patch60_timestamp()
    json_path = SNAPSHOT_SHADOW_PLANS_DIR / f"{ts}_{SNAPSHOT_SHADOW_EXPORT_PREFIX}.json"
    md_path = SNAPSHOT_SHADOW_PLANS_DIR / f"{ts}_{SNAPSHOT_SHADOW_EXPORT_PREFIX}.md"
    json_path.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding="utf-8")
    lines = [
        "# Patch 85 Shadow Restore Export",
        "",
        "Mode: EXPORT ONLY. No copy or restore authority exists.",
        f"Generated: `{payload.get('created_at')}`",
        f"Plans: **{len(rows)}**",
        "",
    ]
    for row in rows[:100]:
        lines.append(f"- `{row.get('created_at')}` status=`{row.get('status')}` validate=`{row.get('validate_status')}` files=`{row.get('planned_files')}` path=`{row.get('path')}`")
    md_path.write_text("\n".join(lines), encoding="utf-8")
    print()
    print("── Snapshot Shadow Export ───────────────────────────")
    print("  Mode      : EXPORT ONLY")
    print("  JSON      :", json_path)
    print("  Markdown  :", md_path)
    print("  Plans     :", len(rows))
    print("  Authority : NO copy, NO restore, NO project writes")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "SNAPSHOT_SHADOW_EXPORT_WRITTEN", str(json_path), str(md_path), f"plans={len(rows)}")


