def cmd_engine_approved_lockfile_candidate(session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    candidate = _patch74_build_candidate()
    path = _patch74_save_candidate(candidate)
    counts = candidate.get("review_counts", {})
    print()
    print("── Engine Approved Lockfile Candidate ───────────────")
    print("  Mode        : CANDIDATE ONLY")
    print("  Engine files: unchanged")
    print("  Authority   : NO — not a final canonical lockfile")
    print(f"  Ledger rows : {counts.get('total')} total approved={counts.get('approved')} deferred={counts.get('deferred')} pending={counts.get('pending')} rejected={counts.get('rejected')}")
    print(f"  Included    : {candidate.get('included_count')}")
    print(f"  Excluded    : {candidate.get('excluded_count')}")
    print(f"  Status      : {candidate.get('status')}  validation={candidate.get('validation_status')}")
    print(f"  Path        : {path}")
    print("  Sample included entries:")
    for row in candidate.get("candidate_entries", [])[:12]:
        print(f"    - {row.get('engine_base')} -> {row.get('canonical_path_candidate')} ({row.get('decision_confidence')})")
    extra = len(candidate.get("candidate_entries", [])) - 12
    if extra > 0:
        print(f"    ... {extra} more included entries")
    print("  Exclusion summary:")
    reasons = {}
    for row in candidate.get("excluded_entries", []):
        reasons[row.get("reason", "unknown")] = reasons.get(row.get("reason", "unknown"), 0) + 1
    for k, v in sorted(reasons.items()):
        print(f"    - {k}: {v}")
    print("  Result      : ENGINE_APPROVED_LOCKFILE_CANDIDATE_WRITTEN")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_APPROVED_LOCKFILE_CANDIDATE_WRITTEN", str(path), f"included={candidate.get('included_count')} excluded={candidate.get('excluded_count')}", f"validation={candidate.get('validation_status')}")


def cmd_engine_approved_lockfile_show(engine_base: str, session_id: str) -> None:
    from agents.forge.memory import write_audit_entry
    candidate, path, err = _patch74_load_latest_candidate(build_if_missing=True)
    print()
    print("── Engine Approved Lockfile Show ───────────────────")
    print("  Mode      : READ ONLY")
    print(f"  Candidate : {path}")
    print(f"  Query     : {engine_base}")
    if err or not candidate:
        print(f"  Status    : {err or 'candidate unavailable'}")
        print("──────────────────────────────────────────────────────")
        print()
        return
    row, section = _patch74_find_row(candidate, engine_base)
    print(f"  Matches   : {1 if row else 0}")
    print("  Rule      : exact engine_base match only")
    print()
    if not row:
        print("  No exact engine_base match found in candidate or exclusions.")
    elif section == "candidate":
        print(f"  Engine base : {row.get('engine_base')}")
        print("  Status      : CANDIDATE_INCLUDED")
        print(f"  Path        : {row.get('canonical_path_candidate')}")
        print(f"  Review      : {row.get('review_status')}")
        print(f"  Confidence  : {row.get('decision_confidence')}")
        print(f"  Variants    : {row.get('variant_count')}")
        print("  Authority   : NO — candidate only")
        if row.get("required_human_checks"):
            print("  Required checks:")
            for c in row.get("required_human_checks", []):
                print(f"    - {c}")
        if row.get("cautions"):
            print("  Cautions:")
            for c in row.get("cautions", []):
                print(f"    - {c}")
    else:
        print(f"  Engine base : {row.get('engine_base')}")
        print("  Status      : EXCLUDED")
        print(f"  Review      : {row.get('review_status')}")
        print(f"  Hold family : {row.get('is_hold_family')}")
        print(f"  Eligible?   : {row.get('future_lockfile_eligible')}")
        print(f"  Reason      : {row.get('reason')}")
        print(f"  Path draft  : {row.get('recommended_keep_path')}")
    print("──────────────────────────────────────────────────────")
    print()
    write_audit_entry(session_id, "ENGINE_APPROVED_LOCKFILE_SHOW", engine_base, f"section={section}", "read-only")


