def cmd_snapshot_live_approval_gate(arg: str, session_id: str) -> None:
    """Validate the live restore approval token gate. Usage: snapshot-live-approval-gate [latest|path]"""
    from agents.forge.memory import write_audit_entry
    path = _snapshot_live_approval_resolve_path(arg)
