def cmd_snapshot_live_restore_dry_run(arg: str, session_id: str) -> None:
    """Create a Patch 91 live restore candidate dry-run receipt. Usage: snapshot-live-restore-dry-run [latest|token_path]"""
    from agents.forge.memory import write_audit_entry
    report, json_path, md_path = _snapshot_live_restore_dry_run_build(arg or "latest")
