SNAPSHOT_LIVE_BACKUP_COPY_SCHEMA_VERSION = "snapshot_live_restore_backup_copy_v1_patch93"
SNAPSHOT_LIVE_BACKUP_COPY_POLICY_VERSION = "patch93_live_restore_backup_copy_sandbox_v1"
SNAPSHOT_LIVE_BACKUP_COPY_DIR = MEMORY_DIR / "live_restore_backups_v1"
